INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5gqcfoa6x094xwqsmbd1xiyt', 'tech', 'Welche typischen Merkmale kennzeichnen chemisch Laugen?', '["Enthalten OH⁻-Ionen, seifig, pH > 7","Enthalten H⁺-Ionen, sauer, pH < 7","Sind neutral, pH = 7","Sind gasförmig und geruchlos"]'::jsonb, 0, NULL, true, NOW(), NOW());
