INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c4n3rdge3pfct50tn9phjpc60', 'tech', 'Wie ist die pH-Wert-Skala aufgebaut?', '["Kontrolle der Dosierpumpen nach Betriebsvorschrift","Von 1 bis 10 wie vorgeschrieben nach Trinkwasserverordnung","Von -7 bis +7 gemäß Betriebsanweisung im Rahmen der Eigenkontrolle","Von 0 (stark sauer) über 7 (neutral) bis 14 (stark basisch)"]'::jsonb, 3, NULL, true, NOW(), NOW());
