INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ceiwm7gorx8wbv6r7q60n4ely', 'tech', 'Was versteht man unter pH-hautneutral?', '["pH-Wert von ca. 5,5 (natürlicher Säureschutzmantel der Haut)","Kommunikation mit dem Betreiber unter Betriebsbedingungen","pH-Wert von 9,0 gemäß Gefährdungsbeurteilung","pH-Wert von 3,0 nach Wartungsplan nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
