INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ccr31v6ma8me2suhjjrvpk1og', 'tech', 'Welche Folgen können Abweichungen des pH-Wertes im Beckenwasser haben?', '["Kalibrierung der Messgeräte nach Trinkwasserverordnung","Nur optische Veränderungen laut Betriebshandbuch","Verminderte Chlorwirkung, Haut-/Augenreizungen, Korrosion","Kontrolle der Wärmetauscher nach Desinfektionsplan"]'::jsonb, 2, NULL, true, NOW(), NOW());
