INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c28p6ohjtx7o1ctlq72ati55f', 'tech', 'Warum muss das Beckenwasser Desinfektionskraft haben?', '["Um eingetragene Keime durch Badegäste kontinuierlich abzutöten","Um das Wasser blau zu färben nach Wartungsplan","Um die Temperatur zu halten nach DIN 19643","Um den pH-Wert zu senken im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cslvw89ap2fvl9kb7u2kvx0q2', 'tech', 'Was versteht man unter der Anomalie des Wassers?', '["Koordination mit externen Dienstleistern nach UVV","Wasser gefriert bei -10°C gemäß Betriebsanweisung","Wasser ist bei 0°C am dichtesten nach Herstellervorgabe","Wasser hat bei 4°C seine größte Dichte und dehnt sich beim Gefrieren aus"]'::jsonb, 3, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('coq7l88t5ljr0t6orfoyv84uc', 'tech', 'Wie wirkt sich die Anomalie des Wassers im Winter im Freibad aus?', '["Eis bildet sich an der Oberfläche, 4°C warmes Wasser sinkt auf den Grund","Das Wasser gefriert von unten nach oben nach Wartungsplan","Das Becken platzt sofort nach Hygieneplan nach Sicherheitsvorschrift","Prüfung der Notfallpläne und Rettungsketten bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
