INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('crrbt9au5o22h0t799zdwb6ej', 'tech', 'Was versteht man unter Füllwasser?', '["Nur Regenwasser durch geschultes Personal","Wasser zum erstmaligen Befüllen oder Nachfüllen des Beckens","Überprüfung der Wasseraufbereitungsanlage","Gebrauchtes Beckenwasser bei ordnungsgemäßem Betrieb"]'::jsonb, 1, NULL, true, NOW(), NOW());
