INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c2yo5tom0sm2h138ytabk3u93', 'tech', 'Was ist Schwallwasser?', '["Frisch zugeführtes Wasser bei Standardbedingungen","Kontrolle der Beschilderung gemäß Gefährdungsbeurteilung","Filtrat nach DIN 19643 gemäß Prüfprotokoll nach geltender Vorschrift","Durch Badende und Wellenbewegung über die Rinne abfließendes Wasser"]'::jsonb, 3, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cdk7gz6w9kb91ryvh32yopmw5', 'tech', 'Warum wird Frischwasser dem Schwallwasserbehälter zugegeben?', '["Um den Behälter zu reinigen nach Hygieneplan nach technischer Regel","Um die Temperatur zu senken nach Betriebsvorschrift","Um Wasserverluste auszugleichen und die Wasserqualität zu verbessern","Verwaltung der Schließfächer bei ordnungsgemäßem Betrieb"]'::jsonb, 2, NULL, true, NOW(), NOW());
