INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cilc2n5zf6778hlhxal0dinhk', 'tech', 'Was sind chemische Messparameter des Beckenwassers?', '["Freies Chlor, gebundenes Chlor, pH-Wert, Redoxpotential","Nur die Wassertemperatur nach Desinfektionsplan","Nur die Trübung im Rahmen der Eigenkontrolle","Nur der Salzgehalt nach Dienstanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
