INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('csfpxykfifj3l3nb0htartnlb', 'tech', 'Wie wirkt sich Regen auf das Wasser im Freibad aus?', '["Inspektion der Schwallwasserbehälter","Nur positiv durch Frischwasserzufuhr","Verdünnung, pH-Änderung, erhöhter Schmutzeintrag","Es wird nur wärmer nach aktueller Norm"]'::jsonb, 2, NULL, true, NOW(), NOW());
