INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cnk8a4r5aa3bre8idfsdpphlh', 'tech', 'Was versteht man unter einem Indikator?', '["Ein Stoff, der durch Farbänderung den pH-Wert oder andere Werte anzeigt","Ein Messgerät für Temperatur laut Herstellerangaben","Durchführung von Evakuierungsübungen nach Sicherheitsvorschrift","Eine Pumpe im laufenden Betrieb durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9sp19s92f7fmy1ozjvas62m9', 'tech', 'Wofür steht der Begriff "Redox"?', '["Reduktion und Oxidation","Reinigung und Desinfektion","Regelung und Dosierung","Rückspülung und Oxidation"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0a44pkaafjmre9b0rip0bf0h', 'tech', 'Was versteht man unter dem Redoxpotential des Beckenwassers?', '["Die Temperatur des Wassers gemäß Betriebsanweisung nach Trinkwasserverordnung","Filterbettinspektion durchführen nach UVV nach DIN 19643","Die Wasserhärte im laufenden Betrieb im Rahmen der Eigenkontrolle","Das elektrische Potential, das die Oxidations-/Reduktionskraft des Wassers anzeigt"]'::jsonb, 3, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cll970w2hcq7h961f95szaiu9', 'tech', 'Was sind die reduzierenden Stoffe im Beckenwasser?', '["Verunreinigungen wie Harnstoff, Schweiß, Hautschuppen","Chlor und Ozon im Routinebetrieb bei korrekter Anwendung","Nur Metalle nach Dienstanweisung nach DIN 19643","Nur Gase durch den Betreiber nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
