INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c947b9h643232cm5zbnfekr20', 'tech', 'Wie wird das Redoxpotential gemessen?', '["Mit einer Redoxmesszelle (Platin-Elektrode gegen Bezugselektrode)","Mit einem Thermometer und dokumentieren durch den Betreiber","Mit einer Küvette in regelmäßigen Abständen","Mit einer Waage nach DIN 19643 nach Dienstanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cvimaspns9d8tyt74kt56qkg5', 'tech', 'Was besagt die Redox-Spannungsreihe?', '["Sie ordnet Metalle nach ihrem Bestreben, Elektronen abzugeben","Sie zeigt Temperaturen von Metallen durch den Betreiber","Sie misst Wasserdrücke durch Fachpersonal","Sie zeigt Stromstärken und dokumentieren"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c13fdjah9g2uui5do1ro2y5dr', 'tech', 'Was ist Kalomel?', '["Quecksilber(I)-chlorid, verwendet als Bezugselektrode bei Redoxmessungen","Ein Filtermedium nach Hygieneplan bei Standardbedingungen","Ein Desinfektionsmittel laut Betriebshandbuch laut Herstellerangaben","Eine Chlorverbindung laut RKI-Empfehlung durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9gpk8zcx0cgd4zrny07akfi7', 'tech', 'Worüber gibt das Redoxpotential Auskunft?', '["Filterspülung zeitnah durchführen laut RKI-Empfehlung","Über den Wasserstand nach Dienstanweisung bei vorschriftsmäßigem Betrieb","Über den Salzgehalt laut Betriebshandbuch durch geschultes Personal","Über das Verhältnis von oxidierenden zu reduzierenden Stoffen im Wasser"]'::jsonb, 3, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxlfs8f8ih6ck2cnp1nrplt3x', 'tech', 'Was sind Karbonathärtebildner des Wassers?', '["Calcium- und Magnesiumhydrogencarbonat","Natriumchlorid im Routinebetrieb","Kaliumnitrat nach geltender Vorschrift","Eisensulfat im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cz0pfuoby6h1wdfvl14frio69', 'tech', 'Wie setzt sich die Wasserhärte zusammen?', '["Aus Karbonathärte (temporär) und Nichtkarbonathärte (permanent)","Nur aus dem Kalkgehalt und dokumentieren im Regelbetrieb","Nur aus dem Salzgehalt nach Herstellervorgabe","Nur aus dem pH-Wert nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cemjujg9xb9n2jh0orhd6zmpz', 'tech', 'Wodurch entsteht die Karbonathärte?', '["Durch gelöste Calcium- und Magnesiumhydrogencarbonate","Durch Chlorzugabe nach Hygieneplan und dokumentieren","Durch hohe Temperaturen nach Dienstanweisung","Durch Filterung gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctp3slnmatktmu8j5bt6z2dvb', 'tech', 'Wie hängen Karbonathärte und Wassertemperatur zusammen?', '["Bei steigender Temperatur fällt Kalk aus (Karbonathärte sinkt)","Temperatur hat keinen Einfluss nach Dienstanweisung","Bei steigender Temperatur steigt die Härte","Nur bei Frost ändert sich die Härte nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctm09n6kg9w0rfy5kjn3c8ovn', 'tech', 'Wann und wie kommt es zur Kalkausfällung?', '["Bei Erwärmung oder CO₂-Verlust fällt Calciumcarbonat aus","Nur bei Kälte nach technischer Regel durch geschultes Personal","Nur bei Chlorzugabe nach Sicherheitsvorschrift","Niemals im Schwimmbad nach DIN 19643 nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
