INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cikvb9cudfsoxnzxeykfr39it', 'tech', 'Was tun Sie bei zu niedrigem Redoxpotential?', '["Chlordosierung erhöhen, Umwälzung und Filterung prüfen","Rückspülintervall anpassen nach Wartungsplan","Wassertemperatur erhöhen gemäß Prüfprotokoll","Badebetrieb fortsetzen im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cv7p6vj2e9q1as1wqwcinqqjg', 'tech', 'Warum sind die Redoxmesswerte bei Salzwasser niedriger?', '["Weil die Chlorid-Ionen die Messung beeinflussen","Weil Salzwasser wärmer ist nach Herstellervorgabe","Weil der pH-Wert höher ist laut RKI-Empfehlung","Salzwasser hat keinen Redox-Unterschied"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c4c2e4cszcf7z4ll7s1mh7d4v', 'tech', 'Welche Redoxanzeige erhalten Sie, wenn reduzierende Stoffe im Beckenwasser überwiegen?', '["Niedrige Redoxspannung (unter 750 mV)","Hohe Redoxspannung (über 800 mV)","Genau 750 mV nach Vorschrift","Der Wert ist nicht messbar"]'::jsonb, 0, NULL, true, NOW(), NOW());
