INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cyfg70v9xxvm996zmvbdk7wcy', 'tech', 'Was sagt ein Redoxwert von 750 mV bei Süßwasser?', '["Ausreichende Desinfektionskraft des Beckenwassers","Zu niedriger Wert, sofort handeln","Gefährlich hoher Wert in regelmäßigen Abständen","Kein aussagekräftiger Wert durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cvecw8fgf2pwe04qwlf35c57a', 'tech', 'Welche Aggregatzustände hat Wasser?', '["Fest (Eis), flüssig (Wasser), gasförmig (Wasserdampf)","Nur flüssig und fest nach DIN 19643","Nur flüssig und gasförmig laut Herstellerangaben","Nur fest und gasförmig nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
