INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c8hzflyzo5h1l4lrvjasg3p9p', 'tech', 'Mit welchen Geräten wird der pH-Wert bestimmt?', '["Chlorgehalt manuell kontrollieren im Normalbetrieb","Photometer, pH-Meter (Glaselektrode), Teststreifen, Indikatorlösung","Rettungsgeräte überprüfen gemäß Prüfprotokoll","Frischwasserzufuhr regulieren wie vorgeschrieben"]'::jsonb, 1, NULL, true, NOW(), NOW());
