INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cl41j3bto4ybssxzyu8jwt2c7', 'tech', 'Was versteht man unter dem Siedepunkt des Wassers?', '["Temperatur, bei der das Wasser verdampft (100°C bei Normaldruck)","Temperatur, bei der das Wasser gefriert bei Standardbedingungen","Der Punkt, an dem Salz sich auflöst durch den Betreiber","Die maximale Wassertemperatur im Becken im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
