INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxkooqbny8mxoyt2q22zvsqok', 'tech', 'Was versteht man unter einem Naturbad?', '["Ein Bad mit biologischer Wasseraufbereitung ohne Chemikalien","Ein Hallenbad mit Pflanzen durch den Betreiber","Ein Freibad mit Chlorung unter Aufsicht","Ein Bad nur für Naturfreunde nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
