INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('chizocs9293bdmnfcfnmragan', 'tech', 'Wie sind im Bad Säuren und Laugen zu lagern?', '["Getrennt voneinander, in gekennzeichneten Auffangwannen","Zusammen in einem Regal nach Hygieneplan","In der Schwimmhalle laut RKI-Empfehlung","Im Umkleidebereich nach Vorschrift nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
