INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('crbvom7mv0payh4l574pqrkzb', 'tech', 'Welche Arten von Sicherheitskennzeichen gibt es?', '["Verbots-, Warn-, Gebots-, Rettungs- und Brandschutzzeichen","Nur Verbotszeichen nach Hygieneplan nach Trinkwasserverordnung","Nur Warnzeichen nach technischer Regel","Nur Rettungszeichen im Normalbetrieb im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c63aexevndtseb6rv1ho2efa9', 'tech', 'Bei welchen Arbeiten muss Gehörschutz getragen werden?', '["Bei Arbeiten über 85 dB (z.B. Hochdruckreiniger, Maschinen)","Nur beim Schwimmen im Routinebetrieb nach aktueller Norm","Nie im Schwimmbad unter Betriebsbedingungen","Nur beim Telefonieren nach DIN 19643 durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('certwcy7ngk8hta9kq22t56e5', 'tech', 'Was bedeutet die Angabe dB?', '["Dezibel – Maßeinheit für Schallpegel/Lautstärke","Destilliertes Beckenwasser unter Aufsicht","Deutsche Betriebsordnung nach technischer Regel","Desinfektion Becken unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1tvaubdehuokudkoihwv1nze', 'tech', 'Wie sind elektrische Anlagen in Bädern abzusichern?', '["Durch FI-Schutzschalter, Schutzisolierung und regelmäßige Prüfung","Gar nicht speziell nach UVV nach DIN 19643 nach Sicherheitsvorschrift","Nur mit einer normalen Sicherung gemäß Infektionsschutzgesetz","Nur im Trockenbereich nach Wartungsplan im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c79liq3hx92rpm2ywzk05su8e', 'tech', 'Worauf ist beim Verwenden von Atemschutzmasken zu achten?', '["Richtiger Filtertyp, Dichtsitz, regelmäßiger Filterwechsel","Auf nichts Besonderes nach Trinkwasserverordnung","Nur auf die Farbe durch Fachpersonal gemäß Gefährdungsbeurteilung","Nur auf die Größe im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9z2oeg7dmkac21t7h2x9i6b1', 'tech', 'Was ist der AGW-Wert (früher MAK-Wert)?', '["Arbeitsplatzgrenzwert – maximale Konzentration eines Stoffes am Arbeitsplatz","Allgemeiner Gewichtswert nach Trinkwasserverordnung","Automatischer Grenzwertsensor nach Desinfektionsplan","Abwassergrenzwert im Rahmen der Eigenkontrolle nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctj1wr621irmacqeotwr4l7k1', 'tech', 'Wo ist der AGW-Wert im Bäderbereich besonders von Bedeutung?', '["Im Chlorgasraum und beim Umgang mit Chemikalien","Nur im Büro unter Aufsicht nach aktueller Norm","Nur in der Kasse durch geschultes Personal","Nur im Ruheraum wie vorgeschrieben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0ey5yvynlv09myhuxpnghafl', 'tech', 'Was sind S+R-Sätze in Sicherheitsdatenblättern?', '["Sicherheitsratschläge (S) und Risikohinweise (R) – heute H- und P-Sätze","Sport- und Rettungsregeln gemäß Betriebsanweisung","Schwimm- und Rutschhinweise gemäß Gefährdungsbeurteilung","Sonder- und Regelleistungen und dokumentieren nach Desinfektionsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cpalkzsynajdk1b0v68p7rsq2', 'tech', 'Welche Reinigerarten werden in Bädern unterschieden?', '["Saure, basische (alkalische), neutrale Reiniger und Desinfektionsmittel","Nur Seife nach Hygieneplan laut Betriebshandbuch","Nur Wasser nach Sicherheitsvorschrift bei Standardbedingungen","Nur Chlorreiniger nach Vorschrift unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cjte1mzqtjtjekngwfyja94nv', 'tech', 'Was versteht man unter einer Grundreinigung?', '["Intensive, turnusmäßige Komplettreinigung aller Bereiche","Tägliches kurzes Wischen nach Betriebsvorschrift","Nur Fensterputzen im Routinebetrieb im laufenden Betrieb","Nur Beckenreinigung bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cd5i2e931as6xvf5hllrqfqtz', 'tech', 'Wie können gefüllte Becken gereinigt werden?', '["Mit Unterwasserreiniger/Poolsauger und Beckenbürsten","Nur durch Ablassen des Wassers nach Betriebsvorschrift","Gar nicht, nur bei leerem Becken und dokumentieren","Mit einem Besen bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0cqrl6k1gsjy9oo4vfubpufw', 'tech', 'Mit welchen Reinigern sollten Beckenumgänge gereinigt werden?', '["Saure oder neutrale Reiniger, je nach Verschmutzungsart","Nur mit klarem Wasser nach Trinkwasserverordnung","Mit Spülmittel unter Aufsicht nach DIN 19643","Mit Geschirrspülpulver und dokumentieren"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cuhhww1ccsa7apdh3c6eelzjj', 'tech', 'Wie oft sollten Beckenumgänge gereinigt werden?', '["Täglich, bei starker Nutzung mehrmals täglich","Einmal pro Woche laut Herstellerangaben","Einmal pro Monat und dokumentieren","Nur bei sichtbarem Schmutz nach DIN 19643"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c4wdlez2vhsnnkkdo2i17go5o', 'tech', 'Wie oft sollten Umkleiden gereinigt werden?', '["Täglich, bei starkem Besuch mehrmals täglich","Einmal pro Woche nach Vorschrift","Einmal pro Monat gemäß Gefährdungsbeurteilung","Nur nach Beschwerden nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('czm627795cyuyav5f5r2u5cld', 'tech', 'Warum ist eine tägliche Badreinigung erforderlich?', '["Zur Hygiene, Vermeidung von Keimverbreitung und Rutschgefahr","Nur wegen der Optik nach technischer Regel","Ist nicht erforderlich nach Herstellervorgabe","Nur vom Gesundheitsamt gefordert durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ck827jksndb5247h5iwjwwd20', 'tech', 'Was ist zu tun, bevor Sie eine Überlaufrinne reinigen?', '["Wasserstand absenken, Rinne vom Kreislauf trennen","Einfach reinigen ohne Vorbereitung","Nur den Filter abstellen nach Betriebsvorschrift","Die Gäste informieren wie vorgeschrieben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cg73chnl26k4ou2v0e92fe2sg', 'tech', 'Wonach richtet sich die Auswahl des Reinigers?', '["Nach Art der Verschmutzung und dem zu reinigenden Material","Nach dem Preis nach aktueller Norm durch den Betreiber","Nach der Farbe bei Standardbedingungen","Nach der Flaschengröße gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cauhskve8z3ki2exx7x96vcy1', 'tech', 'Wie sind empfindliche Bauteile zu reinigen?', '["Mit neutralen Reinigern und weichen Materialien, keine Scheuermittel","Mit aggressiven Säuren durch Fachpersonal nach technischer Regel","Mit Drahtbürsten wie vorgeschrieben gemäß Infektionsschutzgesetz","Mit Hochdruckreiniger laut Herstellerangaben im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('crl0f6lvl2b360ryaq1vbbcss', 'tech', 'Was sind typische Substanzen saurer Reiniger?', '["Salzsäure, Phosphorsäure, Zitronensäure, Essigsäure","Natronlauge durch den Betreiber wie vorgeschrieben","Ammoniak nach Dienstanweisung gemäß Prüfprotokoll","Seife nach Desinfektionsplan gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cx2vcw2teawuo9tf5sftfppa5', 'tech', 'Was sind typische Substanzen basischer Reiniger?', '["Natronlauge, Kalilauge, Soda, Ammoniak","Salzsäure durch den Betreiber","Essigsäure durch geschultes Personal","Zitronensäure nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('coz08n1r2r51kgp1cj1rtiit9', 'tech', 'Wann werden neutrale Reiniger eingesetzt?', '["Bei empfindlichen Oberflächen und bei der täglichen Unterhaltsreinigung","Nur bei Grundreinigungen laut RKI-Empfehlung im Rahmen der Betriebsführung","Nur bei starken Verschmutzungen nach Trinkwasserverordnung","Nie im Bäderbereich nach technischer Regel nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cdb8mbxi0qbegea3u1fc1jp8c', 'tech', 'Was ist ein Kombi-Reiniger?', '["Ein Reiniger mit gleichzeitiger desinfizierender Wirkung","Ein Reiniger für zwei Personen unter Aufsicht","Ein Gemisch aus Säure und Lauge wie vorgeschrieben","Ein rein mechanischer Reiniger nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgsky0dmm892wees0z6khfbg1', 'tech', 'Wo werden saure Reiniger eingesetzt?', '["Gegen Kalk, Urinstein, Rost, mineralische Ablagerungen","Gegen Fettschmutz im laufenden Betrieb","Gegen Schimmel bei vorschriftsmäßigem Betrieb","Nur auf Holz gemäß Prüfprotokoll durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('caf82r4jqgih2qukvphly30b0', 'tech', 'Wo werden basische (alkalische) Reiniger eingesetzt?', '["Gegen Fette, Öle, organische Verschmutzungen","Gegen Kalkablagerungen nach aktueller Norm","Gegen Rost bei vorschriftsmäßigem Betrieb","Nur auf Glas bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ce0pvkjkvdjhm7tcoe2aic773', 'tech', 'Wo werden neutrale Reiniger eingesetzt?', '["Auf empfindlichen Oberflächen, bei der täglichen Unterhaltsreinigung","Nur gegen starke Verschmutzungen nach UVV in regelmäßigen Abständen","Nur in der Küche nach Betriebsvorschrift im Routinebetrieb","Nur im Außenbereich nach aktueller Norm bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cx5ma16acnssr38o57o4m1ev2', 'tech', 'Wie wirken saure Reiniger?', '["Sie lösen Kalk und mineralische Ablagerungen auf","Sie lösen Fette auf nach Wartungsplan","Sie desinfizieren gemäß Infektionsschutzgesetz","Sie neutralisieren Gerüche nach Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cvc8545a42zqur19snouacxdn', 'tech', 'Wie wirken basische Reiniger?', '["Sie lösen Fette und organische Verschmutzungen","Sie lösen Kalk auf nach Betriebsvorschrift","Sie desinfizieren nur gemäß Prüfprotokoll","Sie polieren Oberflächen bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cv8d0i5rm6io3wgw91cuytnie', 'tech', 'Wie wirken neutrale Reiniger?', '["Schonende Reinigung durch Tenside ohne aggressive pH-Wirkung","Stark ätzend nach Herstellervorgabe nach Dienstanweisung","Stark kalkauflösend nach DIN 19643 bei korrekter Anwendung","Stark desinfizierend bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgco6ozvo5hflm5n3mwal77b2', 'tech', 'Was sind Netzmittel?', '["Stoffe die die Oberflächenspannung des Wassers herabsetzen","Stoffe zum Festigen von Geweben nach Betriebsvorschrift","Stoffe zum Trocknen nach UVV wie vorgeschrieben","Stoffe zum Erhitzen nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckx3ugjw3723c6ushtrphxckx', 'tech', 'Was sind Emulgatoren?', '["Stoffe die nicht mischbare Flüssigkeiten (Fett/Wasser) verbinden","Stoffe die Kalk lösen gemäß Prüfprotokoll im Routinebetrieb","Stoffe die desinfizieren laut RKI-Empfehlung","Stoffe die Wasser färben laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c84q1ynk1iqulqupe3j46tjo0', 'tech', 'Wann benutzt man Reiniger mit Lösungsmittel?', '["Bei hartnäckigen öl- und fetthaltigen Verschmutzungen","Bei Kalkablagerungen laut Herstellerangaben","Bei leichtem Staub nach Sicherheitsvorschrift","Nie im Bäderbereich durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ca19izycccpx8szllg6913nk1', 'tech', 'Was sind Tenside (WAS)?', '["Waschaktive Substanzen, die die Oberflächenspannung herabsetzen","Wasseraktive Salze bei vorschriftsmäßigem Betrieb","Wasserabweisende Stoffe nach technischer Regel","Wärmeaktivierende Substanzen im Routinebetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c21pg2o6mrovcpvdlj6psr5ac', 'tech', 'Warum muss das Zusammenkommen von Beckenwasser und Flächenreinigern verhindert werden?', '["Es können giftige Gase (z.B. Chlorgas) entstehen","Es passiert nichts nach Trinkwasserverordnung","Es riecht nur unangenehm nach UVV","Das Beckenwasser wird nur trüb nach Desinfektionsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctmsvd2542b51i1o4cqcwsfx4', 'tech', 'Warum sollen Flächenreiniger nicht antrocknen?', '["Rückstände können Oberflächen angreifen und sind schwer zu entfernen","Kein besonderer Grund bei korrekter Anwendung","Nur aus optischen Gründen im Routinebetrieb im Regelbetrieb","Weil sie dann besser riechen gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cbdryya44v4uj4obx77tevi32', 'tech', 'Warum ist bei Reinigern auf die Einwirkzeit zu achten?', '["Für optimale Wirkung; zu kurz = unwirksam, zu lang = Materialschäden","Egal wie lange im Rahmen der Eigenkontrolle nach DIN 19643","Nur für den Geruch wichtig im Routinebetrieb im laufenden Betrieb","Hat keinen Einfluss laut RKI-Empfehlung durch Fachpersonal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cv5ky5iiv9lwv5dll5l9go707', 'tech', 'Was versteht man unter der mechanischen Unterstützung einer Reinigung?', '["Einsatz von Bürsten, Schrubber, Maschinen zur physischen Schmutzentfernung","Nur chemische Reinigung gemäß Betriebsanweisung nach Sicherheitsvorschrift","Nur Hochdruckreiniger nach technischer Regel nach Herstellervorgabe","Nur Einweichen gemäß Gefährdungsbeurteilung durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5v15hjzqatjb0lmeaq0hmy2h', 'tech', 'Mit welchen Reinigern entfernen Sie den Speckrand eines Beckens?', '["Alkalische/basische Reiniger (fettlösend)","Saure Reiniger nach aktueller Norm","Nur klares Wasser bei korrekter Anwendung","Neutrale Reiniger durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cpsnw3yx4sfcqn29gcx0zx46e', 'tech', 'Welche Bäderarten gibt es?', '["Hallenbad, Freibad, Kombibad, Erlebnisbad, Naturbad, Thermalbad","Nur Hallenbäder gemäß Betriebsanweisung laut Herstellerangaben","Nur Freibäder in regelmäßigen Abständen durch geschultes Personal","Nur Erlebnisbäder gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9p0zcyj98su2wmlq8ce9psz4', 'tech', 'Was bedeutet "biologisch abbaubar"?', '["Der Stoff kann durch Mikroorganismen in der Umwelt zersetzt werden","Der Stoff ist giftig nach DIN 19643 laut Betriebshandbuch","Der Stoff ist nicht abbaubar bei ordnungsgemäßem Betrieb","Der Stoff ist radioaktiv durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cuju0wmlko419cettol5d5g7m', 'tech', 'Welche Richtlinien gelten für den Bau und Betrieb von Bädern?', '["DIN 19643, KOK-Richtlinien, DGfdB, GUV, Landesbauordnung","Keine besonderen Richtlinien gemäß Betriebsanweisung","Nur interne Regeln gemäß Prüfprotokoll","Nur EU-Richtlinien bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('csw2964xnefkkjzlgdo471434', 'tech', 'Welche besonderen Anforderungen gelten für ein Lehrschwimmbecken?', '["Verstellbarer Hubboden, geringe Tiefe, gute Sicht, warme Wassertemperatur","Nur ein normales Becken durch geschultes Personal","Mindestens 3m tief im Rahmen der Eigenkontrolle nach Hygieneplan","Keine besonderen Anforderungen unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cqq7cbzz2w6vecx6kljui7ozu', 'tech', 'Wie sollen Beckenboden und Beckenausstiege beschaffen sein?', '["Rutschfest, trittsicher, leicht zu reinigen","Glatt und poliert gemäß Gefährdungsbeurteilung","Aus Holz im Regelbetrieb nach aktueller Norm","Beliebig im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c6yla3eoknc1e70q2shtnxs6p', 'tech', 'Welche Sicherheitsvorschriften gelten für Springerbecken und Sprunganlagen?', '["Mindest-Wassertiefe, Abstände, Geländer, rutschfeste Oberflächen","Keine besonderen Vorschriften nach Betriebsvorschrift","Nur ein Warnschild unter Aufsicht bei Standardbedingungen","Nur Aufsichtspflicht wie vorgeschrieben im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0y1txwc5zogqrsn1oefspgwx', 'tech', 'Welche Aufgabe erfüllt der Schlitten (die Walze) bei einem Sprungbrett?', '["Verstellung der Federspannung und Sprungweite","Dekoration laut RKI-Empfehlung","Beleuchtung im Normalbetrieb bei ordnungsgemäßem Betrieb","Rutschfestigkeit laut Betriebshandbuch"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ci2vkbjh9ipkn7avaf0ptrvv0', 'tech', 'Welche Wassertiefen werden unter Sprungbrettern gefordert?', '["1m-Brett: min. 3,40m Tiefe, 3m-Brett: min. 3,80m Tiefe","1m-Brett: 1m Tiefe, 3m-Brett: 3m Tiefe","1m für beide gemäß Betriebsanweisung","5m für beide nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmh8y39ajpdqjfaod7lkm9ene', 'tech', 'Was versteht man unter einem Variobecken?', '["Ein Becken mit verstellbarem Hubboden für verschiedene Wassertiefen","Ein Becken mit verschiedenen Farben nach UVV","Ein rundes Becken nach DIN 19643 laut Herstellerangaben","Ein Becken ohne Wasser durch den Betreiber bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('clg23ij2p39ltz3rjyvyuz259', 'tech', 'Wie sind Variobecken hinsichtlich der Beckenhydraulik zu durchströmen?', '["Gleichmäßig über den gesamten Beckenquerschnitt","Nur von einer Seite durch den Betreiber","Nur von oben im laufenden Betrieb","Gar nicht nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cdzkeafyt33ch0x6p5leg6o06', 'tech', 'Was ist bei der Bedienung von Hubböden zu beachten?', '["Sicherheitsabschaltung, Quetschsicherung, nur geschultes Personal","Keine besonderen Vorschriften nach aktueller Norm","Jeder darf sie bedienen gemäß Betriebsanweisung","Nur im Notfall laut Betriebshandbuch nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9vk5uznhh4he97qg5a6ahxwe', 'tech', 'Welche Arten von Wellenmaschinen gibt es?', '["Luftkammer-, Klappen- und Tauchkörper-Wellenmaschinen","Nur elektrische Wellenmaschinen im Routinebetrieb","Nur manuelle Wellenerzeuger nach UVV","Es gibt nur eine Art nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
