INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cp9zq4svhqytkv8r4yz6gc0aj', 'tech', 'Was ist das Symbol für einen Schutzklasse-I-Geräte?', '["Schutzleiteranschluss (Erde-Symbol)","Doppelte Isolierung (Quadrat im Quadrat)","Keine Kennzeichnung","Tropfwasserschutz"]'::jsonb, 0, NULL, true, NOW(), NOW());
