INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c6jo1navh7d7oyu1t8i99xtxb', 'tech', 'Wie wird Gleichstrom dargestellt?', '["DC oder mit geradem Strich (—)","AC oder mit Wellenlinie (~)","Mit einem Kreis gemäß Infektionsschutzgesetz","Mit einem Dreieck im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
