INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9mef40xc0b4eu8voy0m78yu3', 'tech', 'Wie kann sich elektrischer Strom bei Kontakt auf den Menschen auswirken?', '["Muskelverkrampfung, Herzrhythmusstörung, Verbrennungen, Tod","Gar nicht bei niedrigen Spannungen im Regelbetrieb","Nur leichtes Kribbeln nach DIN 19643 gemäß Prüfprotokoll","Nur bei Gleichstrom gefährlich durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c774agqpk7o1krmstwsjdzc05', 'tech', 'Was versteht man unter Korrosion?', '["Zerstörung von Werkstoffen durch chemische oder elektrochemische Reaktion mit der Umgebung","Reinigung von Metallen gemäß Infektionsschutzgesetz laut RKI-Empfehlung","Verstärkung von Materialien durch Fachpersonal im Rahmen der Betriebsführung","Lackierung von Oberflächen nach DIN 19643 im Routinebetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cn731laoiqus2rsv2jfu6qzjg', 'tech', 'Welche Korrosionsarten werden unterschieden?', '["Chemische, elektrochemische und biologische Korrosion","Nur Rost nach Sicherheitsvorschrift","Nur Lochfraß in regelmäßigen Abständen","Nur Flächenkorrosion im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('chmyeluv0w2rf8fdv64ycu0i4', 'tech', 'Wie entsteht chemische Korrosion?', '["Durch direkte Reaktion des Metalls mit aggressiven Stoffen (Säuren, Laugen, Gase)","Nur durch Strom gemäß Prüfprotokoll durch geschultes Personal","Nur durch Wasser im laufenden Betrieb bei Standardbedingungen","Nur durch Hitze im Rahmen der Betriebsführung im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckshdy19cn87wzrfkb9mnmmty', 'tech', 'Wie kann es zur Korrosion an Werkstoffen kommen?', '["Durch Feuchtigkeit, aggressive Chemikalien, Kontakt verschiedener Metalle","Nur durch Sonneneinstrahlung bei vorschriftsmäßigem Betrieb","Nur durch Kälte nach Hygieneplan bei ordnungsgemäßem Betrieb","Korrosion tritt nur an Eisen auf nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c3q0qaduqhh60o6qot7foxsng', 'tech', 'Wie entsteht elektrochemische Korrosion?', '["Durch ein galvanisches Element (zwei verschiedene Metalle in einem Elektrolyt)","Durch Sonnenlicht nach Betriebsvorschrift nach Desinfektionsplan","Durch Hitze allein nach geltender Vorschrift gemäß Betriebsanweisung","Durch Wind durch Fachpersonal nach Dienstanweisung gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cfm1kueatboo482ck9bahzl5z', 'tech', 'Was bedeutet aktiver Korrosionsschutz?', '["Kathodischer Schutz durch Opferanoden oder Fremdstrom","Nur Anstreichen im Normalbetrieb bei korrekter Anwendung","Nur Abdecken laut RKI-Empfehlung nach Hygieneplan","Kein Schutz nötig nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cs7hgh70yxar71bw3f7d9yjf6', 'tech', 'Was bedeutet passiver Korrosionsschutz?', '["Beschichtungen, Lackierungen, Verzinkung als Barriere","Elektrischer Schutz unter Aufsicht laut Herstellerangaben","Chemischer Zusatz im Wasser nach Vorschrift","Keine Maßnahme nach DIN 19643 nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmwl87v2c81bmml4efi4hlyfk', 'tech', 'Was bedeutet konstruktiver Korrosionsschutz?', '["Vermeidung von Korrosion durch geeignete Materialwahl und Konstruktion","Nur Anstreichen bei vorschriftsmäßigem Betrieb","Nur Opferanoden nach aktueller Norm bei ordnungsgemäßem Betrieb","Nur Verzinkung nach Betriebsvorschrift im Regelbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
