INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwhh8za4w08p28potmolo8l2j', 'tech', 'Welche Vor- und Nachteile hat eine GFK-Innenbeschichtung bei Filtern?', '["Vorteil: korrosionsbeständig; Nachteil: kann bei Beschädigung unterwandert werden","Nur Vorteile nach Betriebsvorschrift durch geschultes Personal","Nur Nachteile gemäß Betriebsanweisung durch Fachpersonal","Weder Vor- noch Nachteile gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
