INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ccqgwjj7n8x09oy7ecwcq0uyo', 'tech', 'Wie sind Handläufe bei Beckenausstiegsleitern beschaffen?', '["Aus Edelstahl, durchgehend, ergonomisch geformt, korrosionsbeständig","Aus Holz unter Aufsicht durch Fachpersonal im Normalbetrieb","Aus normalem Stahl gemäß Betriebsanweisung gemäß Gefährdungsbeurteilung","Aus Kunststoff bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgg07qb9j8psz8onx821mr30f', 'tech', 'Welche Aufgaben erfüllen Rinnenabdeckroste?', '["Abdeckung der Überlaufrinne, Trittsicherheit, Verhinderung von Unfällen","Nur Dekoration gemäß Prüfprotokoll im Routinebetrieb","Nur Schallschutz laut RKI-Empfehlung gemäß Gefährdungsbeurteilung","Keine besondere Aufgabe nach Desinfektionsplan nach Sicherheitsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('czuevut1xtovhwq163r3ufwux', 'tech', 'Wie sind Rinnenabdeckroste zu warten?', '["Regelmäßig reinigen, auf Bruchstellen und Befestigung prüfen","Gar nicht nach Hygieneplan gemäß Betriebsanweisung","Nur einmal jährlich ansehen im Routinebetrieb","Nur bei Bedarf in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
