INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0rp7gs5iebchfqrs4gwo0gp4', 'tech', 'Welche Schutzausrüstung benötigen Sie bei Arbeiten an Chlorungsanlagen?', '["Chlorgasmaske, Schutzhandschuhe, Schutzbrille, Schutzkleidung","Keine besondere Ausrüstung laut Betriebshandbuch","Nur eine Sonnenbrille gemäß Prüfprotokoll","Nur Handschuhe nach Herstellervorgabe im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
