INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c8pb84nywenjcpmel5ajzmpfz', 'tech', 'Was sind Vorteile der Überwinterung ohne Wasser im Becken?', '["Gute Inspektionsmöglichkeit, Reparaturen möglich","Keine Vorteile nach Trinkwasserverordnung","Weniger Kosten immer wie vorgeschrieben","Besserer Frostschutz im Routinebetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
