INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('co4rynm3y9qns5uiscf5nedcg', 'tech', 'Was sind Vorteile der Überwinterung mit Wasser im Becken?', '["Schutz gegen Grundwasserauftrieb, Stabilisierung der Beckenwände","Keine Vorteile nach Vorschrift nach Desinfektionsplan","Das Wasser bleibt sauber in regelmäßigen Abständen","Man kann im Winter schwimmen bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgiw4d6t86fcaxc8j7gf8rrbi', 'tech', 'Welche Maßnahmen sind zur Überwinterung von Freibädern zu treffen?', '["Leitungen entleeren, Eisdruckpolster einsetzen, Technik konservieren","Keine besonderen Maßnahmen nach geltender Vorschrift","Nur Zaun abschließen im Rahmen der Betriebsführung","Nur Wasser ablassen gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cz2nguyc07nuscjxpnt69aaop', 'tech', 'Wie lassen sich Werkstoffe generell einteilen?', '["In Metalle, Kunststoffe, Keramik und Naturstoffe","Nur in Metalle und Holz nach Desinfektionsplan","Nur in Kunststoffe nach Hygieneplan","Nur in Glas und Stein nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
