INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('crkkn1mbmentmanhb8t13c8dt', 'tech', 'Welche physikalischen Eigenschaften von Werkstoffen sind im Bäderbereich wichtig?', '["Dichte, Wärmeleitfähigkeit, Schmelzpunkt, elektrische Leitfähigkeit","Nur die Farbe und dokumentieren gemäß Prüfprotokoll","Nur der Geruch nach Betriebsvorschrift nach Hygieneplan","Nur das Gewicht im Normalbetrieb laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('chw3l6m51gy84g7as4w349mdv', 'tech', 'Welche mechanischen Eigenschaften von Werkstoffen sind im Bäderbereich wichtig?', '["Festigkeit, Härte, Elastizität, Verschleißbeständigkeit","Nur der Preis nach Dienstanweisung laut Herstellerangaben","Nur die Farbe durch den Betreiber durch geschultes Personal","Nur der Geschmack gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cyx30iem8amcxgrczcmw15kle', 'tech', 'Welche chemischen Eigenschaften von Werkstoffen sind im Bäderbereich wichtig?', '["Korrosionsbeständigkeit, Säure-/Laugenbeständigkeit, Chlorbeständigkeit","Nur die Brennbarkeit nach UVV bei vorschriftsmäßigem Betrieb","Nur die Löslichkeit nach technischer Regel unter Aufsicht","Keine besonderen nach Trinkwasserverordnung im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1yh4hl70nuom2rzpbs6nebng', 'tech', 'Wie unterscheidet man Pumpen im Bäderbereich?', '["Verdrängerpumpen (Kolben, Membran) und Strömungspumpen (Kreisel)","Nur nach Größe und dokumentieren nach Vorschrift","Nur nach Farbe nach UVV nach Trinkwasserverordnung","Nur nach Hersteller nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9qupwd66awsckva19ilqxkrg', 'tech', 'Wo werden Kolbenpumpen im Bäderbereich eingesetzt?', '["Zur Chemikaliendosierung (geringe Mengen, hoher Druck)","Als Hauptumwälzpumpe nach DIN 19643 im Normalbetrieb","Zur Beckenentleerung durch geschultes Personal","Zur Wellenanlage wie vorgeschrieben nach Sicherheitsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('crp8qcm671lpk2f7qysxeiv5p', 'tech', 'Wie funktioniert eine Membranpumpe?', '["Eine flexible Membran erzeugt durch Hin- und Herbewegung einen Pumpeffekt","Durch Rotation eines Rades nach geltender Vorschrift","Durch Schwerkraft gemäß Infektionsschutzgesetz gemäß Betriebsanweisung","Durch Dampfdruck nach Betriebsvorschrift im Regelbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cj426xcrh9o8sz3mjc08bnirn', 'tech', 'Wo werden Membranpumpen im Bäderbereich eingesetzt?', '["Zur Dosierung von Chemikalien (Chlor, Flockungsmittel, pH-Korrektur)","Als Hauptumwälzpumpe nach geltender Vorschrift","Zur Schwallwasserentsorgung gemäß Infektionsschutzgesetz","Als Feuerlöschpumpe nach Betriebsvorschrift laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1m4kwn93ykdksd1y6dgltfft', 'tech', 'Was ist ein Vorteil von Kolbenpumpen?', '["Sehr genaue Dosierung auch bei kleinen Mengen","Sehr hoher Volumenstrom im Normalbetrieb","Keine Wartung nötig bei ordnungsgemäßem Betrieb","Sehr leise gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
