INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cifaxz79wwd55bhcrrcno3wth', 'tech', 'Wie können Kreiselpumpen zwischen Nass- und Trockenteil abgedichtet werden?', '["Durch Gleitringdichtungen oder Stopfbuchsen","Gar nicht gemäß Gefährdungsbeurteilung","Mit Klebeband nach Herstellervorgabe","Mit Silikon nach Trinkwasserverordnung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckftr0j5pu4vmpks5fdw2tz9j', 'tech', 'Was ist das Prinzip einer Wasserstrahlpumpe?', '["Treibwasser erzeugt Unterdruck durch hohe Geschwindigkeit (Venturi-Effekt)","Elektromotor treibt Laufrad gemäß Prüfprotokoll bei ordnungsgemäßem Betrieb","Kolben erzeugt Druck nach Dienstanweisung gemäß Betriebsanweisung","Membran bewegt sich im Regelbetrieb nach Sicherheitsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckgh6ji5a0zbtqh5hmd282tuk', 'tech', 'Nach welchem Prinzip arbeitet eine Injektorpumpe?', '["Nach dem Venturi-Prinzip (Strahlpumpe)","Nach dem Kolbenprinzip bei vorschriftsmäßigem Betrieb","Nach dem Membranprinzip durch geschultes Personal","Nach dem Kreiselprinzip bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
