INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cystwwo9fjxz3m5brt4zci0gd', 'tech', 'Was ist ein Gegenstromapparat?', '["Ein Wärmetauscher, in dem zwei Medien in entgegengesetzter Richtung fließen","Eine Schwimmhilfe nach aktueller Norm durch geschultes Personal","Ein Wasserrutschenteil nach Hygieneplan im Rahmen der Eigenkontrolle","Ein Filtergehäuse und dokumentieren nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c801nihji8do4gqx7aab2hf1e', 'tech', 'Welche Möglichkeiten gibt es, Schwimmbeckenwasser zu erwärmen?', '["Wärmetauscher, Solarthermie, Wärmepumpe, direkte Beheizung","Nur Sonnenlicht bei ordnungsgemäßem Betrieb","Nur Elektroheizstab im Regelbetrieb nach aktueller Norm","Gar nicht im laufenden Betrieb im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgq04xvnuqqc18pbc6dhkd1j2', 'tech', 'Wie kann Duschwasser in Bädern erwärmt werden?', '["Wärmetauscher, Durchlauferhitzer, Speichersystem, Solaranlage","Nur durch Sonnenlicht im laufenden Betrieb","Nur durch Dampf nach Hygieneplan nach Herstellervorgabe","Gar nicht durch Fachpersonal gemäß Prüfprotokoll"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cqse1ywn44psujrceadqwstr2', 'tech', 'Wie kann man in Schwimmbädern die Wärmeenergieausnutzung verbessern?', '["Wärmerückgewinnung aus Abluft und Abwasser, Beckenabdeckung","Fenster öffnen im Rahmen der Betriebsführung","Heizung abschalten durch geschultes Personal","Mehr Badegäste einladen in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
