INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cg9rgmymqm8gmqsdge2pgj4rk', 'tech', 'Was sind Hauptaufgaben der Klimaanlage eines Hallenbades?', '["Be- und Entlüftung, Entfeuchtung, Temperierung der Hallenluft","Nur Kühlung unter Aufsicht laut Betriebshandbuch","Nur Heizung nach Wartungsplan nach Sicherheitsvorschrift","Nur Geruchsbeseitigung nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
