INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgg1nt9cyvex6s8b4rr4ka5u1', 'tech', 'Was ist der Taupunkt der Luft?', '["Die Temperatur, bei der die Luft mit Wasserdampf gesättigt ist und Kondensation eintritt","Die maximale Lufttemperatur nach Desinfektionsplan bei Standardbedingungen","Die minimale Raumtemperatur durch Fachpersonal nach Herstellervorgabe","Der Siedepunkt von Wasser unter Aufsicht nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cbini78dyeyvd3uhorirwd6sj', 'tech', 'Was passiert bei Ausfall der Schwimmhallenklimaanlage?', '["Kondenswasser an Wänden und Decke, Korrosion, Schimmelgefahr","Nichts Besonderes laut Herstellerangaben","Das Wasser kühlt ab nach Sicherheitsvorschrift","Die Beleuchtung fällt aus nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c425vzb71grqw1bs8nfkvsx89', 'tech', 'Warum kann ein Mensch in der Sauna ca. 100°C kurzzeitig ertragen?', '["Trockene Luft leitet Wärme schlecht, Schweiß kühlt durch Verdunstung","Der Körper ist hitzeresistent laut Betriebshandbuch","Die Temperatur wird falsch gemessen im laufenden Betrieb","Der Mensch spürt keine Hitze nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cujhl0w9s1ar282p6h0rrx7bj', 'tech', 'Bei welchen Temperaturen vermehren sich Legionellen besonders?', '["Zwischen 25 und 50 °C (optimal etwa 35-45 °C)","Unter 10 °C nach Sicherheitsvorschrift","Nur über 80 °C gemäß Gefährdungsbeurteilung","Nur bei 0 °C gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cp1n7yowryl6bvle9jkjze96n', 'tech', 'Wie wird Legionellenprophylaxe in Bädern durchgeführt?', '["Wassertemperatur >60°C im Speicher, regelmäßige thermische Desinfektion, Durchfluss sichern","Nur durch Chlorung im Routinebetrieb nach Desinfektionsplan nach geltender Vorschrift","Gar nicht nach UVV durch geschultes Personal bei vorschriftsmäßigem Betrieb","Durch Abkühlung des Wassers und dokumentieren nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('campnwd5s83zc7avxqjb55401', 'tech', 'Wie kann Wärmerückgewinnung in Bädern durchgeführt werden?', '["Wärmetauscher in Abluft und Abwasser zur Vorwärmung von Frischluft/Frischwasser","Gar nicht möglich nach Hygieneplan unter Betriebsbedingungen","Nur durch Solaranlagen nach Vorschrift laut Betriebshandbuch","Durch Fenster öffnen nach Sicherheitsvorschrift nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('csajhgca67tl999fmbglhqlzr', 'tech', 'Welchen Sinn haben Schwimmbadabdeckungen?', '["Reduzierung von Verdunstung, Wärmeverlust und Verschmutzung","Nur Dekoration nach aktueller Norm wie vorgeschrieben","Nur Schutz vor Regen im laufenden Betrieb","Kein besonderer Nutzen bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
