INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c184qxpartvei2jq6kplhaxtb', 'tech', 'Wie wirkt sich starker Algenbefall im Becken aus?', '["Glatte Oberflächen (Rutschgefahr), Trübung, erhöhter Chlorverbrauch","Gar nicht nach aktueller Norm im Normalbetrieb","Nur optisch störend im Routinebetrieb nach Hygieneplan","Nur leichter Geruch laut Betriebshandbuch gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
