INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cse40lpcvff485iepyuz20tkt', 'tech', 'Worauf ist bei der Algenbekämpfung besonders zu achten?', '["Richtige Dosierung, ausreichend Chlor, gute Durchströmung, Ursache beseitigen","Auf nichts Besonderes gemäß Prüfprotokoll unter Betriebsbedingungen","Nur mehr Wasser hinzufügen im Rahmen der Betriebsführung","Nur die Temperatur senken nach Dienstanweisung bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
