INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ch4qqol4h2c6lzk0zdcrbbjq4', 'tech', 'Was bedeutet "sporizid"?', '["Sporentötend (Abtötung von Dauerformen)","Pilztötend im Rahmen der Eigenkontrolle","Bakterientötend in regelmäßigen Abständen","Algentötend laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('czgzm18tbjgj7ajurowng7kxq', 'tech', 'Welche Algenarten kommen in Freibädern häufig vor?', '["Grünalgen, Blaualgen (Cyanobakterien), Braunalgen","Nur Rotalgen und dokumentieren nach Herstellervorgabe","Keine Algen gemäß Infektionsschutzgesetz","Nur Kieselalgen unter Aufsicht nach DIN 19643"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxbkb86lmd5zzs7hh3xe0v5qq', 'tech', 'Welche Wirkstofftypen gibt es für die Flächendesinfektion?', '["Aldehyde, Alkohole, Halogene, quartäre Ammoniumverbindungen","Nur Chlor bei Standardbedingungen unter Betriebsbedingungen","Nur Seife nach geltender Vorschrift durch geschultes Personal","Nur Wasser nach aktueller Norm durch Fachpersonal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c627i93t8hdf3bzqwx51d4ne6', 'tech', 'Welche Anforderungen werden an gute Desinfektionsmittel gestellt?', '["Breites Wirkungsspektrum, schnelle Wirkung, materialschonend, umweltverträglich","Nur billig gemäß Gefährdungsbeurteilung laut RKI-Empfehlung","Nur gut riechend nach Betriebsvorschrift nach geltender Vorschrift","Keine besonderen Anforderungen unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c7jhaptvs1bf6zdqcwohx29cv', 'tech', 'Wie wirken Aldehyde als Desinfektionsmittel?', '["Sie denaturieren Eiweiße von Mikroorganismen","Sie lösen Kalk auf gemäß Betriebsanweisung","Sie senken den pH-Wert nach Herstellervorgabe","Sie erwärmen das Wasser bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgu7nafvzuff9ej1r73nmkjhf', 'tech', 'Wie wirken Phenolderivate als Desinfektionsmittel?', '["Sie schädigen die Zellmembran von Mikroorganismen","Sie erhöhen den pH-Wert nach Hygieneplan","Sie senken die Temperatur unter Betriebsbedingungen","Sie lösen Fette im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ch7iqm13yu26mp78rxwp9vv4a', 'tech', 'Wie wirken Alkohole als Desinfektionsmittel?', '["Sie denaturieren Eiweiße und lösen Lipide der Zellmembran","Sie lösen nur Kalk im Normalbetrieb nach Vorschrift","Sie wirken nur bei hohen Temperaturen wie vorgeschrieben","Sie sind unwirksam laut Betriebshandbuch"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c6faex2cbubrvoj1i35w9vsea', 'tech', 'Wie wirken quartäre Ammoniumverbindungen (QUAT)?', '["Sie stören die Zellmembran von Bakterien","Sie lösen Kalk nach Trinkwasserverordnung","Sie erhöhen den pH-Wert nach Dienstanweisung","Sie wirken nur gegen Viren"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cke6ln5pwx0y0ndnmxh10jboa', 'tech', 'Wie wirken Halogene (z.B. Chlor) als Desinfektionsmittel?', '["Oxidation und Zerstörung der Zellstrukturen von Mikroorganismen","Nur durch Erwärmung laut Betriebshandbuch","Nur durch Abkühlung gemäß Prüfprotokoll unter Betriebsbedingungen","Durch mechanische Wirkung nach Desinfektionsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cf44fat3ndl4krrn0wn2jhb1o', 'tech', 'Was ist ein Vorteil von Alkoholen bei der Flächendesinfektion?', '["Schnelle Wirkung, verdunsten rückstandsfrei","Sehr billig wie vorgeschrieben","Wirken gegen Sporen durch geschultes Personal","Kein Geruch gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cin8bu5bddmlpfhlwoldo7djd', 'tech', 'Was ist ein Nachteil von Alkoholen bei der Flächendesinfektion?', '["Keine Sporentwirksamkeit, brennbar, schnelle Verdunstung","Zu teuer und dokumentieren im Rahmen der Eigenkontrolle","Zu langsam in regelmäßigen Abständen nach Wartungsplan","Hinterlassen Rückstände bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cac3xugvh0ypsaimykou8of7e', 'tech', 'Was ist ein Nachteil von QUAT bei der Flächendesinfektion?', '["Eingeschränktes Wirkungsspektrum, nicht sporentwirksam","Zu teuer gemäß Prüfprotokoll gemäß Infektionsschutzgesetz","Zu schnelle Wirkung gemäß Betriebsanweisung","Zu starker Geruch im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cnfv94w0vqrlnh08bldgz00c5', 'tech', 'Was sind Arbeitsgrundsätze bei der Desinfektion von Flächen?', '["Richtige Konzentration, Einwirkzeit beachten, Fläche vorher reinigen","Keine besonderen Grundsätze in regelmäßigen Abständen","Einfach draufsprühen nach Trinkwasserverordnung","Nur bei sichtbarem Schmutz nach UVV im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cry4bcxef2293ukdciliuzghx', 'tech', 'Was versteht man unter "gebunden wirksames Chlor"?', '["Chlor, das mit Stickstoffverbindungen (Harnstoff etc.) zu Chloraminen reagiert hat","Frisch dosiertes Chlor nach Sicherheitsvorschrift im Normalbetrieb","Chlor im Gasraum nach aktueller Norm nach Dienstanweisung","Chlor in der Flasche nach Betriebsvorschrift gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cm385kbrbletqbljoltuad3j5', 'tech', 'Was versteht man unter "frei wirksames Chlor"?', '["Aktives Chlor (HOCl/OCl⁻), das noch Desinfektionskraft hat","Chlor, das verbraucht ist nach Betriebsvorschrift","Gebundenes Chlor laut RKI-Empfehlung nach Desinfektionsplan","Chlorgas in der Luft im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ccw6ovvpi2fbplxa1tskx1ewn', 'tech', 'Was sind Chloramine und wie entstehen sie?', '["Verbindungen aus Chlor und Stickstoff (Harnstoff, Schweiß), verursachen Chlorgeruch","Chlor in reiner Form gemäß Gefährdungsbeurteilung durch geschultes Personal","Chlor im Gasraum bei Standardbedingungen in regelmäßigen Abständen","Natürliche Chlorverbindungen bei korrekter Anwendung im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cyyvpy3t9lzqijjrpcbthzsbx', 'tech', 'Was sind THMs (Trihalogenmethane)?', '["Desinfektionsnebenprodukte aus der Reaktion von Chlor mit organischen Stoffen","Ein Filtertyp nach Betriebsvorschrift nach Dienstanweisung","Ein Pumpenmodell im laufenden Betrieb im Rahmen der Betriebsführung","Ein Reinigungsmittel bei ordnungsgemäßem Betrieb laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxs5oegjh6skomzq3upt9wzx2', 'tech', 'Welche Richtwerte gelten für freies Chlor im Beckenwasser?', '["0,3–0,6 mg/L (Hallenbad), bis 1,2 mg/L (Freibad)","5–10 mg/L und dokumentieren durch geschultes Personal","0,01 mg/L bei korrekter Anwendung","Kein Richtwert gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c3744ocotm6xkocu7fm48iql5', 'tech', 'Wer führt die Kontrollen der Wasserqualität in öffentlichen Bädern durch?', '["Das Gesundheitsamt und akkreditierte Labore","Nur der Bademeister nach aktueller Norm","Die Feuerwehr nach technischer Regel","Die Polizei wie vorgeschrieben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cntkcyndhpa5d2ot58taz6efw', 'tech', 'Welche Messfehler können bei der kolorimetrischen Wasseruntersuchung auftreten?', '["Verschmutzte Küvetten, falsche Reagenzien, abgelaufene Testmittel","Keine Fehler möglich nach aktueller Norm nach Sicherheitsvorschrift","Nur Temperaturfehler nach geltender Vorschrift","Nur Ablesefehler durch geschultes Personal laut Betriebshandbuch"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('co6xppvfhhjjb3xr0r8gkbaf1', 'tech', 'Wie unterscheiden sich kolorimetrische und photometrische Wasseruntersuchungen?', '["Kolorimetrisch: Farbvergleich mit Auge; photometrisch: elektronische Messung der Lichtabsorption","Kein Unterschied im Routinebetrieb gemäß Betriebsanweisung unter Aufsicht","Kolorimetrisch ist genauer nach Trinkwasserverordnung wie vorgeschrieben","Photometrisch nutzt Farbvergleichsscheiben und dokumentieren bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cadf5t5tunijq8q6bdzzw4sny', 'tech', 'Welche Verfahrenskombinationen zur Wasseraufbereitung gibt es nach DIN 19643?', '["Flockung-Filtration-Desinfektion in verschiedenen Kombinationen (z.B. mit Ozon, Adsorption, UV)","Nur Chlorung nach Wartungsplan durch Fachpersonal nach Sicherheitsvorschrift","Nur Filtration nach Trinkwasserverordnung nach Herstellervorgabe","Keine festgelegten Verfahren nach Desinfektionsplan nach UVV im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1gvvtiwobd42h6ev4zo7yj9z', 'tech', 'Warum ist eine gute Beckenwasserdurchströmung erforderlich?', '["Gleichmäßige Verteilung des Desinfektionsmittels und Vermeidung von Totzonen","Nur für Wellenbetrieb nach Vorschrift durch den Betreiber","Nur für die Optik nach geltender Vorschrift im laufenden Betrieb","Ist nicht wichtig gemäß Betriebsanweisung nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c38tznwukf0swiv2kd83zdsa0', 'tech', 'Welche Beckenwasserdurchströmungsarten gibt es?', '["Horizontale, vertikale und gemischte Durchströmung","Nur horizontale im Rahmen der Eigenkontrolle","Nur vertikale im Rahmen der Betriebsführung","Es gibt keine Unterschiede nach UVV"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cioc3su0e66npyayp3klzfoge', 'tech', 'Welche Anforderungen werden an die Beckenwasserdurchströmung gestellt?', '["Gleichmäßig, totzonenfrei, kurze Aufenthaltszeit, guter Austausch","Keine besonderen Anforderungen laut Betriebshandbuch","Nur schnelle Durchströmung und dokumentieren","Nur langsame Durchströmung laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cbtq33rgllgehkoyrl3x6s9jc', 'tech', 'Was sind Totzonen bzw. Totwassergebiete?', '["Bereiche im Becken mit unzureichender Durchströmung und Desinfektion","Die tiefsten Stellen im Becken gemäß Prüfprotokoll","Bereiche ohne Badegäste nach Herstellervorgabe","Bereiche mit zu viel Chlor im Normalbetrieb laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgj8ovpabxf1gjb7q3x9bneu9', 'tech', 'Was versteht man unter dem mittleren stündlichen Förderstrom?', '["Das Wasservolumen, das pro Stunde durch die Aufbereitungsanlage gefördert wird","Die maximale Pumpenleistung in regelmäßigen Abständen","Den Wasserverbrauch der Duschen nach Sicherheitsvorschrift","Die Regenmenge pro Stunde nach Vorschrift gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cs3si133grtm723zvz6relhxe', 'tech', 'Welche Aufgaben erfüllen Überlaufrinnen?', '["Abführung des Schwallwassers, Oberflächenreinigung, Niveauregulierung","Nur Dekoration im Regelbetrieb durch den Betreiber","Nur Wellenbrecher nach Betriebsvorschrift gemäß Infektionsschutzgesetz","Keine besondere Aufgabe nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c6rvdl38gofclx6p2n9ax4kjr', 'tech', 'Welche Rinnensysteme gibt es?', '["Finnische Rinne, Wiesbadener Rinne, Züricher Rinne, Kastenrinne","Nur ein Rinnensystem durch Fachpersonal bei Standardbedingungen","Nur die Wiesbadener Rinne laut RKI-Empfehlung","Nur die Finnische Rinne nach Hygieneplan nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cofaeirovyfuh1bvgybidb1v8', 'tech', 'Was sind Vorteile der Finnischen Rinne?', '["Gute Oberflächenreinigung, geringe Geräuschentwicklung","Sehr billig gemäß Infektionsschutzgesetz","Keine Wartung nötig nach UVV nach Sicherheitsvorschrift","Besser als alle anderen bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cklamrip18oqq5rfeci3peo3s', 'tech', 'Was sind Nachteile der Finnischen Rinne?', '["Hoher baulicher Aufwand, schwer zu reinigen","Keine Nachteile durch den Betreiber","Zu laut im Normalbetrieb nach Herstellervorgabe","Zu teuer im Betrieb im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c6gd9qh2v9av88f9b0zoi90ha', 'tech', 'Was sind Vorteile der Wiesbadener Rinne?', '["Leicht zu reinigen, gute Zugänglichkeit","Keine Vorteile im laufenden Betrieb","Sehr billig gemäß Betriebsanweisung","Geräuschlos nach DIN 19643"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0cno9foiocuvugmaf1sxhe5h', 'tech', 'Was sind Nachteile der Wiesbadener Rinne?', '["Höhere Geräuschentwicklung, Spritzwasser auf Umgang möglich","Keine Nachteile durch den Betreiber laut Betriebshandbuch","Sehr teuer wie vorgeschrieben gemäß Infektionsschutzgesetz","Schwer zu reinigen durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cerp7l9472wszk4mq18owncqy', 'tech', 'Welche Aufgaben erfüllt eine Handfasse?', '["Festhaltemöglichkeit für Schwimmer am Beckenrand","Nur Dekoration unter Aufsicht laut Betriebshandbuch","Wassereinlauf im Regelbetrieb nach DIN 19643","Wasserablauf bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c12a7oqflqg9fn8msx5nyxrfr', 'tech', 'Wie ist eine Finnische Rinne aufgebaut?', '["Unter Wasserspiegel liegende Rinne mit Überlaufkante und Abflusskanal","Eine einfache Regenrinne bei vorschriftsmäßigem Betrieb","Ein offener Kanal am Beckenrand nach Betriebsvorschrift","Eine Rohleitung unter dem Becken nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cdh393giu1hjmi9kn15yz192o', 'tech', 'Welche Aufgaben erfüllt ein Skimmer?', '["Absaugung der Wasseroberfläche zur Entfernung von Verschmutzungen","Nur Wasserzufuhr nach UVV im Rahmen der Eigenkontrolle","Nur Beleuchtung im Rahmen der Betriebsführung","Nur Dekoration nach geltender Vorschrift nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5gj5emu71z6bn244yqmp6kk4', 'tech', 'Wie funktioniert ein Skimmer?', '["Schwimmende Klappe passt sich dem Wasserspiegel an und saugt Oberfläche ab","Durch eine Pumpe am Beckenboden nach Herstellervorgabe","Durch Überlauf wie eine Rinne nach Desinfektionsplan","Durch manuelle Absaugung im Regelbetrieb nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cz4n635bjxvegdzz4jsim4yv9', 'tech', 'Welche Aufgaben hat ein Schwallwasserbehälter?', '["Pufferung von Schwallwasser, Niveauregulierung, Mischpunkt für Chemikalien","Nur Wasserspeicherung im Normalbetrieb nach Dienstanweisung","Nur Filterbehälter nach technischer Regel laut Herstellerangaben","Keine besondere Aufgabe nach Betriebsvorschrift im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgu0f26tlc59urdvglq62o0tv', 'tech', 'Was bedeutet Niveauregulierung beim Schwallwasserspeicher?', '["Ausgleich von Wasserstandsschwankungen im Becken durch Zu-/Ablauf im Behälter","Farbliche Markierung des Wasserstands nach Trinkwasserverordnung","Regelung der Wassertemperatur nach Desinfektionsplan","Steuerung der Beleuchtung nach DIN 19643 nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cm5ptbluc22ze9xocgdvet1v6', 'tech', 'Welche Aufgaben erfüllen Vorfilter?', '["Rückhaltung grober Verschmutzungen vor der Hauptfilteranlage","Nur Desinfektion gemäß Infektionsschutzgesetz","Nur pH-Korrektur nach Sicherheitsvorschrift","Nur Wassererwärmung im Routinebetrieb nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cu9rdpnxyg8lb16t2i948et9c', 'tech', 'Welche Arten von Vorfiltern gibt es?', '["Haarfangsiebe, Grobfilter, Korbfilter","Nur Sandfilter nach technischer Regel","Nur Aktivkohlefilter wie vorgeschrieben","Es gibt keine Vorfilter nach UVV"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cbq4whtzl3mz4euhmw5fhwqnj', 'tech', 'Wie sind Roste, Gitter und Rinnenabdeckungen unfallsicher auszubilden?', '["Rutschfest, kippsicher, fingersicher, belastbar, gut befestigt","Nur angeschraubt nach DIN 19643 nach Hygieneplan","Nur lose aufgelegt nach Wartungsplan wie vorgeschrieben","Keine besonderen Anforderungen nach Trinkwasserverordnung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('claqmswk1f4iqudpak2sjtonq', 'tech', 'Wo finden Sie Vorfilter im Schwimmbad?', '["Vor der Umwälzpumpe, im Schwallwasserbehälter, in der Rinne","Nur nach dem Hauptfilter nach Wartungsplan","Nur im Becken im Normalbetrieb unter Aufsicht","Nirgends nach Betriebsvorschrift gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('chluftuxg6unglekxqiuvr5fm', 'tech', 'Welche Arten von Wasserverunreinigungen gibt es im Bäderbereich?', '["Grob-, fein- und gelöste Verunreinigungen (Haare, Hautschuppen, Harnstoff)","Nur Haare nach aktueller Norm laut Betriebshandbuch","Nur Chlorreste nach Betriebsvorschrift und dokumentieren","Nur Sand gemäß Infektionsschutzgesetz wie vorgeschrieben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwtdjsxz91ji0oddx3xoji4p2', 'tech', 'Was sind Kolloide?', '["Sehr fein verteilte Teilchen (1-100 nm), die weder gelöst noch absetzbar sind","Grobe Verunreinigungen nach Wartungsplan im Rahmen der Eigenkontrolle","Chemische Verbindungen unter Aufsicht nach Dienstanweisung","Filtermedien und dokumentieren laut RKI-Empfehlung unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('chzugbdje5s4blxi7fj29n6j9', 'tech', 'Was sind molekular disperse Stoffe?', '["In Wasser gelöste Stoffe auf molekularer Ebene","Große Schmutzpartikel unter Aufsicht","Sandkörner im laufenden Betrieb","Filtermaterialien bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c47k3u0hu6ouztvtgbiu7e6e6', 'tech', 'Was sind grob disperse Stoffe?', '["Sichtbare, absetzbare Teilchen (Haare, Fasern, Insekten)","Gelöste Salze im Routinebetrieb im Rahmen der Betriebsführung","Kolloide bei ordnungsgemäßem Betrieb nach aktueller Norm","Gase im Wasser durch den Betreiber gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
