INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cusmu2n7xd1wczxlzc4uwxjz3', 'tech', 'Was ist der Unterschied zwischen Einschicht- und Mehrschichtenfilter?', '["Einschicht: ein Filtermaterial; Mehrschicht: verschiedene Materialien übereinander","Kein Unterschied nach technischer Regel nach geltender Vorschrift","Einschicht hat mehr Material nach Wartungsplan nach DIN 19643","Mehrschicht ist kleiner in regelmäßigen Abständen nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cq35qgmpmkqr9au18ty09hf7b', 'tech', 'Welchen Sinn hat die Stützschicht eines Filters?', '["Trägt das Filtermaterial und verhindert Austrag in die Düsen","Nur Dekoration gemäß Betriebsanweisung durch Fachpersonal","Nur Isolierung nach Hygieneplan nach technischer Regel","Keine Funktion wie vorgeschrieben durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cbejwvwe52fb7kte08hjv080b', 'tech', 'Wie können Filtermaterialien wirken?', '["Mechanisch (Siebwirkung), adsorptiv (Anlagerung), biologisch (Abbau)","Nur mechanisch nach Desinfektionsplan im Normalbetrieb","Nur chemisch nach technischer Regel durch den Betreiber","Nur biologisch durch geschultes Personal nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ccqmg0eiw6afv4tz0sr7fbk8x', 'tech', 'Welche Eigenschaften hat das Filtermaterial Anthrazitkohle?', '["Leicht, grobkörnig, gute mechanische Filtration, lange Standzeiten","Sehr schwer im Normalbetrieb durch Fachpersonal","Löst sich im Wasser unter Aufsicht nach Trinkwasserverordnung","Nur für Trinkwasser in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cp40to019xi7jpau0y0bnkpc0', 'tech', 'Welche Eigenschaften hat das Filtermaterial Kieselgur?', '["Sehr feine Filtration, für Anschwemmfilter geeignet","Sehr grobe Filtration gemäß Gefährdungsbeurteilung","Nur für Gasfilter bei korrekter Anwendung","Nicht für Schwimmbäder geeignet nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmdklp4syyzldrmcrxqc55wyd', 'tech', 'Welche Eigenschaften hat Aktivkornkohle als Filtermaterial?', '["Adsorption von organischen Stoffen und Chloraminen, hohe innere Oberfläche","Nur mechanische Filtration nach Herstellervorgabe","Keine Adsorption im Rahmen der Eigenkontrolle im Normalbetrieb","Nur für Luftfilter durch Fachpersonal laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c94ywtwmosu7eumou9msuf1xi', 'tech', 'Welche Eigenschaften hat dolomitisches Filtermaterial?', '["Entsäuerung des Wassers, pH-Anhebung durch Calciumcarbonat","Nur mechanische Filtration gemäß Infektionsschutzgesetz","Senkt den pH-Wert gemäß Betriebsanweisung","Keine besonderen Eigenschaften unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cjeb6617c7b2qjxjeb7e46x2t', 'tech', 'Welche chemische Filterwirkung hat dolomitisches Filtermaterial?', '["Entsäuerung: CO₂ reagiert mit Dolomit und hebt den pH-Wert","Chlorproduktion durch Fachpersonal gemäß Betriebsanweisung","Säureproduktion gemäß Gefährdungsbeurteilung","Keine chemische Wirkung nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctr16qphhowmkpegxyxk4lf38', 'tech', 'Was versteht man unter katalytisch adsorptiver Filterwirkung?', '["Beschleunigte chemische Umsetzung an der Oberfläche des Filtermaterials","Rein mechanische Filtration im Normalbetrieb nach Dienstanweisung","Thermische Wirkung nach UVV nach technischer Regel","Elektrische Wirkung und dokumentieren bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('caqzs5lkby7bnf5oexxbvfvr3', 'tech', 'Was ist der Unterschied zwischen Schnellfilter und Langsamfilter?', '["Schnellfilter: hohe Filtergeschwindigkeit (10-30 m/h); Langsamfilter: niedrige (0,1-0,3 m/h)","Kein Unterschied unter Aufsicht und dokumentieren nach Betriebsvorschrift","Langsamfilter ist schneller bei vorschriftsmäßigem Betrieb laut Betriebshandbuch","Nur die Größe unterscheidet sich nach aktueller Norm unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ct4w62obmsvplh9e0wqvdamkx', 'tech', 'Welche Vorteile bieten offene Filter?', '["Leichte Kontrolle des Filterzustands, einfache Wartung","Keine Vorteile nach geltender Vorschrift","Höherer Druck möglich nach Trinkwasserverordnung","Kleinere Bauweise laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cyjj33u7j8dmbhal4y1zk72i4', 'tech', 'Was versteht man unter mechanischer Filterwirkung?', '["Rückhaltung von Partikeln durch die Siebwirkung des Filtermaterials","Chemische Umwandlung im laufenden Betrieb nach technischer Regel","Biologischer Abbau im Routinebetrieb durch geschultes Personal","Thermische Behandlung gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cai795u6i84yizg0twjs2z1a7', 'tech', 'Woran erkennen Sie, dass ein Filter rückgespült werden muss?', '["Druckverlust steigt an (Differenzdruck zwischen Ein- und Auslauf)","Der Filter wird lauter laut RKI-Empfehlung im Normalbetrieb","Das Wasser wird wärmer durch den Betreiber nach aktueller Norm","Der Filter wird leichter nach Betriebsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
