INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cagrzhq1ufdtzkdbrrpi80s8r', 'tech', 'Welche Aufgaben hat die Glocke (Trichter) eines Filters?', '["Sammlung und Ableitung des Filtrats, gleichmäßige Wasserverteilung bei Rückspülung","Nur Dekoration nach Desinfektionsplan wie vorgeschrieben","Nur Schallschutz gemäß Gefährdungsbeurteilung im Normalbetrieb","Keine Aufgabe im laufenden Betrieb nach DIN 19643 gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
