INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c3bli75e51hwlq8002wv6sw36', 'tech', 'Wie machen Sie einen Filter im Freibad winterfest?', '["Entleeren, reinigen, Armaturen schützen, Filtermedium belüften","Gar nicht nach Wartungsplan im Regelbetrieb","Nur abschalten in regelmäßigen Abständen durch geschultes Personal","Nur Wasser ablassen laut RKI-Empfehlung gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cggdbaaq94buaw1cpee9cxhd1', 'tech', 'Was ist die Filterhaut und woraus besteht sie?', '["Schmutzschicht auf der Filterbett-Oberfläche aus zurückgehaltenen Partikeln und Flocken","Eine Folie über dem Filter nach Desinfektionsplan nach Hygieneplan","Eine Metallplatte nach geltender Vorschrift bei ordnungsgemäßem Betrieb","Eine Gummidichtung nach Wartungsplan durch Fachpersonal im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
