INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ci3fdyc94nsu5g0mhunqtizym', 'tech', 'Was sind Vorteile von Aktivkohle als Filtermaterial?', '["Sehr gute Adsorption von organischen Stoffen, Chloraminen und Geruchsstoffen","Sehr billig nach Dienstanweisung nach DIN 19643 im laufenden Betrieb","Keine Wartung nötig unter Aufsicht nach Sicherheitsvorschrift","Ewig haltbar im Regelbetrieb bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
