INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ck4e32jnym5bnhuyovxewjup0', 'tech', 'Wie lässt sich die Standzeit eines Anschwemmfilters verlängern?', '["Durch Nachdosierung von Filterhilfsmittel (Sekundäranschwemmung)","Gar nicht bei vorschriftsmäßigem Betrieb bei Standardbedingungen","Durch höheren Druck im Normalbetrieb durch den Betreiber","Durch wärmeres Wasser im Routinebetrieb im Regelbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cyjl3xiiqi5620esrcdj1rxjk', 'tech', 'Wozu dient die Flockung des Rohwassers?', '["Zusammenlagerung feiner Partikel zu größeren Flocken für die Filtration","Nur zur Färbung des Wassers unter Aufsicht nach Desinfektionsplan","Zur Desinfektion bei Standardbedingungen im Rahmen der Eigenkontrolle","Zur Wassererwärmung nach Herstellervorgabe nach Trinkwasserverordnung"]'::jsonb, 0, NULL, true, NOW(), NOW());
