INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ciqesoic1vwnwoua2mnzarsrv', 'tech', 'Welche Flockungsmittel werden in der Bädertechnik eingesetzt?', '["Aluminiumsulfat, Eisen-III-Chlorid, Polyaluminiumchlorid","Nur Kochsalz gemäß Gefährdungsbeurteilung","Nur Chlor durch den Betreiber im Regelbetrieb","Nur Essig bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('codqtnizbfnb1zelre6lj30ss', 'tech', 'Welche Auswirkung hat Flockung mit Aluminiumsulfat auf das Rohwasser?', '["pH-Wert sinkt, Karbonathärte sinkt, Flocken bilden sich","pH-Wert steigt gemäß Betriebsanweisung","Keine Auswirkung durch Fachpersonal bei ordnungsgemäßem Betrieb","Wasser wird warm nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cm4g044cyjbzuzsyn9cinfswl', 'tech', 'Welche Auswirkung hat Flockung mit Natriumaluminat auf das Rohwasser?', '["pH-Wert steigt, Flocken bilden sich, alkalische Reaktion","pH-Wert sinkt stark und dokumentieren","Keine Auswirkung im Normalbetrieb bei ordnungsgemäßem Betrieb","Wasser gefriert nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwb0bms5dhrk3v9fi5bliodxq', 'tech', 'Wie muss die Reaktionsstrecke bei der Flockung beschaffen sein?', '["Ausreichend lang für vollständige Flockenbildung, turbulente Mischung","Möglichst kurz nach Hygieneplan im Rahmen der Eigenkontrolle","Ohne Durchmischung im Regelbetrieb nach UVV in regelmäßigen Abständen","Egal wie lang nach aktueller Norm nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxuitkb6rrjo0t6i1ttivn3rc', 'tech', 'Welchen Sinn hat die Reaktionsstrecke bei der Flockung?', '["Zeit und Raum für die Reaktion des Flockungsmittels mit den Verunreinigungen","Nur Wassererwärmung bei Standardbedingungen durch den Betreiber","Nur Druckerhöhung nach Trinkwasserverordnung gemäß Infektionsschutzgesetz","Kein besonderer Sinn im laufenden Betrieb im Regelbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgzi275a68cbx0mcedimx32s7', 'tech', 'Warum sollen Pumpen vor der Flockungsimpfstelle eingebaut sein?', '["Damit die Pumpe die Durchmischung des Flockungsmittels unterstützt","Aus Platzgründen gemäß Gefährdungsbeurteilung","Wegen der Optik nach Desinfektionsplan laut RKI-Empfehlung","Das ist nicht wichtig gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0wkgm1e42iretnazpgtu9dql', 'tech', 'Wie werden Flockungsmittel eingeimpft?', '["Durch Dosierpumpen in die Rohwasserleitung nach der Umwälzpumpe","Per Hand ins Becken unter Betriebsbedingungen","Durch Schwerkraft nach aktueller Norm gemäß Gefährdungsbeurteilung","Durch Verdampfung im Normalbetrieb gemäß Prüfprotokoll"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckt3egimalusah3yp8zr6ppwo', 'tech', 'Wie setzt sich Aluminiumsulfat (Al₂(SO₄)₃) chemisch zusammen?', '["Aus Aluminium, Schwefel und Sauerstoff","Aus Eisen und Chlor nach Desinfektionsplan","Aus Natrium und Chlor nach technischer Regel","Aus Calcium und Kohlenstoff"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cokub3jfcmkyp0wh9zc3qhmvg', 'tech', 'Was passiert chemisch bei Einsatz von Eisen-III-Chlorid im Wasser?', '["Es bilden sich Eisen(III)-hydroxid-Flocken unter pH-Absenkung","Das Wasser wird rot im laufenden Betrieb","Nichts passiert nach Desinfektionsplan und dokumentieren","Das Wasser gefriert nach DIN 19643 gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cf74vk8ys5fktxfgmmw62zoqa', 'tech', 'Welche chemische Formel hat Aluminiumsulfat?', '["Al₂(SO₄)₃","FeCl₃","NaCl","CaCO₃"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ciepm8hp08czuhma3qg6h8cj8', 'tech', 'Welche chemische Formel hat Eisen-III-Sulfat?', '["Fe₂(SO₄)₃","Al₂(SO₄)₃","FeCl₃","NaOH"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ctne97fo31fqdnjsubnf47rn2', 'tech', 'Wovon ist eine optimale Flockung abhängig?', '["Richtige Dosierung, geeigneter pH-Wert, gute Durchmischung","Nur von der Wassertemperatur durch geschultes Personal","Nur vom Wasserdruck gemäß Infektionsschutzgesetz","Von nichts Besonderem in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ce9aqvzfpqyqfk9yiatsz07mb', 'tech', 'Welche Aufgaben hat ein Marmorreaktionsturm?', '["Entsäuerung des Wassers und Einstellung des Kalk-Kohlensäure-Gleichgewichts","Nur Wassererwärmung in regelmäßigen Abständen gemäß Infektionsschutzgesetz","Nur Filtration gemäß Betriebsanweisung gemäß Gefährdungsbeurteilung","Nur Desinfektion laut RKI-Empfehlung bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cysn9oop12yzu9tsnb9g95qre', 'tech', 'Wie kann man Schwimmbadwasser chemisch enthärten?', '["Durch Zugabe von Enthärtungsmitteln (Phosphate, Komplexbildner)","Durch Erhitzen nach geltender Vorschrift gemäß Gefährdungsbeurteilung","Durch Abkühlen bei ordnungsgemäßem Betrieb","Gar nicht möglich nach technischer Regel bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5qvklmb95l3nlqt0ju8g2p48', 'tech', 'Wie kann man Schwimmbadwasser technologisch enthärten?', '["Durch Ionenaustauscher oder Umkehrosmose","Nur durch Kochen bei Standardbedingungen","Nur durch Einfrieren nach Vorschrift","Nur durch Filtration laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cv9rt2cxuvpe2wphwfu8gjkva', 'tech', 'Wann ist in der Wasseraufbereitung eine pH-Korrektur nötig?', '["Wenn der pH-Wert außerhalb des Sollbereichs (6,5-7,6) liegt","Nie nach Wartungsplan nach geltender Vorschrift","Nur einmal pro Jahr nach Dienstanweisung","Nur bei Neubefüllung nach Desinfektionsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cjhoym9ve8dho1p39rqdownhw', 'tech', 'Welche Mittel werden zur pH-Korrektur eingesetzt?', '["Salzsäure/Schwefelsäure (Senkung), Natronlauge/Soda (Erhöhung)","Nur Kochsalz im laufenden Betrieb laut Betriebshandbuch","Nur Zucker nach technischer Regel und dokumentieren","Nur destilliertes Wasser gemäß Prüfprotokoll"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ch4o65jvh781mg65yca5azv2i', 'tech', 'Warum muss die Säurekapazität des Wassers eingestellt werden?', '["Für ein stabiles Kalk-Kohlensäure-Gleichgewicht und stabile pH-Pufferung","Nur aus optischen Gründen unter Aufsicht bei korrekter Anwendung","Für die Wasserfarbe laut Herstellerangaben nach Betriebsvorschrift","Ist nicht nötig im Rahmen der Eigenkontrolle nach Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ciwg35ek3808lxkf7sgg7y5ci', 'tech', 'Wie kann man eine zu hohe Säurekapazität senken?', '["Durch Säurezugabe (z.B. Salzsäure, Schwefelsäure)","Durch Laugenzugabe nach Vorschrift","Durch Erwärmung gemäß Betriebsanweisung","Durch Chlorzugabe im Regelbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c92rxz7xx1vuftfy1b5dyo00c', 'tech', 'Welche Anforderungen werden an Beckenwasserdesinfektionsmittel gestellt?', '["Breitspektrum-Wirkung, Depotwirkung, verträglich, DIN-zugelassen","Nur günstig gemäß Betriebsanweisung nach Hygieneplan","Nur gut riechend unter Aufsicht nach technischer Regel","Keine Anforderungen im laufenden Betrieb im Routinebetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c8vrb991a3gt10nxi0nv3viwr', 'tech', 'Welche Desinfektionsmittel sind nach DIN 19643 für Beckenwasser erlaubt?', '["Chlorgas, Natriumhypochlorit, Calciumhypochlorit, Chlorelektrolyse, Ozon","Nur Chlorgas durch den Betreiber im laufenden Betrieb","Nur Ozon in regelmäßigen Abständen durch Fachpersonal","Beliebige Mittel gemäß Gefährdungsbeurteilung gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1zkoo5mcx54vlxf24z7vcxwv', 'tech', 'Warum kann die Chlordosierung im Freibad bis 5x höher sein als im Hallenbad?', '["UV-Strahlung baut Chlor ab, höhere Verschmutzung durch Umwelteinflüsse","Weil Freibäder größer sind laut Herstellerangaben","Weil das Wasser kälter ist nach UVV bei vorschriftsmäßigem Betrieb","Das stimmt nicht durch geschultes Personal im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cni6qcacdxc9wjpzceimoc9cs', 'tech', 'Welche Eigenschaften hat Chlor?', '["Gelbgrünes, giftiges Gas, schwerer als Luft, stechend riechend","Farbloses, geruchloses Gas im Regelbetrieb","Leichter als Luft nach DIN 19643 nach Trinkwasserverordnung","Ungiftig und geruchlos bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c7nehebyj9aciw0y1ybu7tovj', 'tech', 'Welche Eigenschaften hat Ozon?', '["Starkes Oxidationsmittel, instabil, zerfällt zu Sauerstoff, stechend riechend","Stabiles Gas im Routinebetrieb nach Hygieneplan nach Desinfektionsplan","Geruchlos laut Betriebshandbuch im Normalbetrieb durch den Betreiber","Schwächer als Chlor bei ordnungsgemäßem Betrieb nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cgiqunvarqesxoatm9vy049w7', 'tech', 'Welche Eigenschaften hat Natriumhypochlorit?', '["Flüssiges Desinfektionsmittel, alkalisch, chlorhaltig, begrenzt lagerfähig","Festes Pulver nach Trinkwasserverordnung im Normalbetrieb","Geruchlos und neutral durch den Betreiber gemäß Gefährdungsbeurteilung","Unbegrenzt haltbar bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5ch9zc1dtubtlxq6aqg7e9f2', 'tech', 'Welche Chlorelektrolyseverfahren gibt es?', '["Salzsäure-Elektrolyse, Rohrzellen-Verfahren, Membranverfahren, Salzwasser-Elektrolyse","Nur ein Verfahren nach technischer Regel nach geltender Vorschrift","Nur manuelle Chlorung im Routinebetrieb nach Sicherheitsvorschrift","Keine Elektrolyseverfahren bei Standardbedingungen bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cp5p5ly124pnhjs68zz2q0244', 'tech', 'Was passiert bei der Chlorelektrolyse?', '["Chlorid-Ionen werden durch Strom zu Chlor oxidiert","Wasser wird zu Dampf nach technischer Regel","Salz wird zu Gold nach DIN 19643 bei ordnungsgemäßem Betrieb","Nichts Besonderes laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cunh9xraecns49dcc7hq96r5g', 'tech', 'Was sind Ausgangsstoffe für die Chlorelektrolyse?', '["Salzsäure, Natriumchlorid-Lösung, Salzwasser","Nur reines Wasser nach Vorschrift","Nur Chlorgas im Normalbetrieb","Nur Natronlauge in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cndw18yseim2csvc0iotda08z', 'tech', 'Wie funktioniert die Elektrolyse von Salzsäure?', '["HCl wird durch Gleichstrom in Chlor (Cl₂) und Wasserstoff (H₂) zerlegt","HCl wird erhitzt nach Herstellervorgabe durch den Betreiber","HCl wird eingefroren nach Wartungsplan nach Desinfektionsplan","HCl wird verdünnt gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cpsruifv0qqvuccjo77jlu86y', 'tech', 'Was ist das Rohrzellen-Elektrolyseverfahren?', '["Elektrolyse in einem rohrförmigen Reaktor mit Anode und Kathode","Filtration in Rohren laut Betriebshandbuch","Desinfektion durch UV-Rohre nach Wartungsplan","Pumpen in Rohrform wie vorgeschrieben bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cloclui72bm2u75uc4o3se9jk', 'tech', 'Wie funktioniert das Membran-Elektrolyseverfahren?', '["Anoden- und Kathodenraum sind durch eine Membran getrennt","Ohne Membran nach geltender Vorschrift","Durch Verdampfung durch den Betreiber gemäß Gefährdungsbeurteilung","Durch Filtration nach Hygieneplan durch Fachpersonal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cve1xkfy6jh32bixwy1r5y8pj', 'tech', 'Wie funktioniert das Salzwasser-Elektrolyseverfahren?', '["Meersalz wird im Wasser gelöst und durch Strom zu Chlor umgewandelt (anodische Oxidation)","Salz wird einfach ins Becken gestreut wie vorgeschrieben im Routinebetrieb","Salzwasser wird abgekocht bei vorschriftsmäßigem Betrieb durch Fachpersonal","Salzwasser wird eingefroren laut RKI-Empfehlung bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxix4oqskuv9ten1qh2w5k5zo', 'tech', 'Wie funktioniert ein Vakuumchlorgasdosiergerät?', '["Chlorgas wird durch Unterdruck (Vakuum) aus der Flasche gesaugt und dem Wasser zugeführt","Chlorgas wird unter Druck eingepresst bei Standardbedingungen","Chlor wird erhitzt im Rahmen der Betriebsführung im Rahmen der Eigenkontrolle","Chlor wird abgekühlt nach UVV nach aktueller Norm bei korrekter Anwendung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0t23aiipafgblb09ujx2g5th', 'tech', 'Wie entsteht unterchlorige Säure (HOCl)?', '["Chlor reagiert mit Wasser: Cl₂ + H₂O → HOCl + HCl","Durch Erhitzen von Chlor gemäß Prüfprotokoll","Durch Mischen von Salz und Essig","Durch UV-Bestrahlung unter Aufsicht"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cm1crf66gsx1ys8f9qw5db63d', 'tech', 'Was ist eine Treibwasserleitung?', '["Wasserleitung, die durch Unterdruck Chlorgas aus dem Dosiergerät ansaugt","Eine Abwasserleitung durch geschultes Personal im Rahmen der Betriebsführung","Eine Gasleitung im Rahmen der Eigenkontrolle nach Trinkwasserverordnung","Eine Heizungsleitung nach Betriebsvorschrift nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwgpy21kthpljdx10nsjka3ok', 'tech', 'Welchen Sinn haben Chlorflaschenhilfsventile?', '["Sicheres Absperren der Chlorflasche ohne direkten Kontakt zum Flaschenventil","Nur Dekoration durch Fachpersonal im Rahmen der Eigenkontrolle","Nur als Ersatzventil nach Hygieneplan im Regelbetrieb","Kein besonderer Sinn laut Betriebshandbuch bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmpwuni7iq3a0gmvoznbqwaq6', 'tech', 'Wie prüfen Sie Chlor führende Leitungen auf Dichtheit?', '["Mit Ammoniakdampf (weißer Nebel bei Chloraustritt) oder Lecksuchspray","Mit Wasser gemäß Gefährdungsbeurteilung im Normalbetrieb","Mit bloßem Auge nach Betriebsvorschrift nach Dienstanweisung","Gar nicht prüfbar nach Wartungsplan nach technischer Regel"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('co2i8vo21vstp9ylx792xfhvs', 'tech', 'Wodurch kann eine Vereisung einer Chlorflasche entstehen?', '["Durch zu hohe Entnahmemenge – das expandierende Gas kühlt die Flasche stark ab","Durch zu warme Umgebung nach aktueller Norm nach Betriebsvorschrift","Durch Sonneneinstrahlung gemäß Prüfprotokoll durch geschultes Personal","Durch zu wenig Entnahme nach technischer Regel in regelmäßigen Abständen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cm3tbx2xqr4eqxnludroweiat', 'tech', 'Welche Sicherheitsvorkehrungen treffen Sie beim Chlorgasflaschenwechsel?', '["Schutzausrüstung anlegen, Raum belüften, Chlorgaswarngerät prüfen, Ventile schließen","Keine besonderen Maßnahmen bei vorschriftsmäßigem Betrieb","Nur Fenster öffnen nach technischer Regel laut RKI-Empfehlung","Nur Handschuhe anziehen unter Aufsicht nach Dienstanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ck14ylby8qmsc3j2megkgavly', 'tech', 'Wo befindet sich die Messzelle des Chlorgaswarngeräts?', '["In Bodennähe, da Chlorgas schwerer als Luft ist","An der Decke nach Herstellervorgabe","In der Mitte des Raums nach Desinfektionsplan","Außerhalb des Gebäudes nach DIN 19643"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1x6k39nr10bklml7ml32j6f1', 'tech', 'Was ist der AGW-Wert für Chlor?', '["0,5 ppm (1,5 mg/m³)","5 ppm durch Fachpersonal","50 ppm laut Betriebshandbuch","0,05 ppm nach Sicherheitsvorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
