INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cp7a6cnntfggs43uvhp7w8p3z', 'tech', 'Welche Bestimmungen gelten für Chlorgasanlagen?', '["Störfallverordnung, Unfallverhütungsvorschriften, TRG, TRGS","Keine besonderen Bestimmungen durch geschultes Personal","Nur interne Regeln gemäß Gefährdungsbeurteilung","Nur Empfehlungen im Normalbetrieb nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c37njkynm93ymd16s3fycjyq5', 'tech', 'Welche Sicherheitsbestimmungen gelten für Chlorgas-Lagerräume?', '["Belüftung, Gaswarnanlage, Berieselungsanlage, Bodenabfluss, feuerhemmende Tür","Keine besonderen Bestimmungen nach Sicherheitsvorschrift","Nur ein Schloss wie vorgeschrieben nach Herstellervorgabe","Nur ein Warnschild gemäß Prüfprotokoll bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cxot4zufvb0i9xe5ay7yegtil', 'tech', 'Wie hoch ist die stündliche Entnahmemenge aus Chlorgasflaschen?', '["Max. ca. 500-700 g/h pro 50-kg-Flasche (um Vereisung zu vermeiden)","10 kg/h laut RKI-Empfehlung im Routinebetrieb","50 kg/h nach Sicherheitsvorschrift nach UVV","Unbegrenzt wie vorgeschrieben nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cx2ganfmpfpi4almmso3oo1d2', 'tech', 'Welchen Sinn hat die Berieselungsanlage im Chlorgasraum?', '["Bindung von austretendem Chlorgas durch Wasser im Havariefall","Nur Kühlung des Raums nach aktueller Norm","Nur Reinigung des Bodens durch Fachpersonal","Nur Brandschutz bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c098vrjgrqcugrduvw6ci5uyx', 'tech', 'Wie gehen Sie mit vollen Chlorgasflaschen um?', '["Aufrecht transportieren, sichern, vor Hitze und Sonneneinstrahlung schützen","Beliebig rollen bei vorschriftsmäßigem Betrieb nach geltender Vorschrift","Werfen und stapeln durch den Betreiber nach Vorschrift","Ohne Vorsichtsmaßnahmen laut Betriebshandbuch nach UVV"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c2ull7775aoidtx3m7k2aa0fd', 'tech', 'Wie gehen Sie mit leeren Chlorgasflaschen um?', '["Ventil schließen, Schutzkappen aufsetzen, als nicht leer behandeln","Einfach entsorgen nach technischer Regel und dokumentieren","Ventil offen lassen gemäß Gefährdungsbeurteilung","In den Müll werfen bei korrekter Anwendung nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5l9nlj290pfdwahpswq5u92q', 'tech', 'Was passiert, wenn Natriumhypochlorit mit Säuren in Kontakt kommt?', '["Es entsteht giftiges Chlorgas!","Nichts passiert wie vorgeschrieben","Es wird neutral bei vorschriftsmäßigem Betrieb","Es entsteht Sauerstoff"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cymvmvucgks08auzh57mbz0bj', 'tech', 'Wie kann es zur Rückverflüssigung von Chlorgas kommen?', '["Durch Druckerhöhung oder starke Abkühlung in der Leitung","Durch Erwärmung im laufenden Betrieb nach Herstellervorgabe","Durch Verdünnung nach geltender Vorschrift","Gar nicht möglich wie vorgeschrieben laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cckea8242s1fqfl05mxkc30st', 'tech', 'Welche Aussagen lassen sich an der Dampfdruckkurve des Chlors ablesen?', '["Zusammenhang zwischen Temperatur und Druck für den Phasenübergang","Nur die Farbe des Chlors gemäß Prüfprotokoll","Nur das Gewicht in regelmäßigen Abständen nach Trinkwasserverordnung","Keine aussagekräftigen Daten nach UVV nach Dienstanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c2etxth3matav1i6evw2x9gwt', 'tech', 'Wie viel Chlor darf man maximal pro Stunde aus einer 50-kg-Flasche entnehmen?', '["Ca. 500-700 g/h","10 kg/h","50 kg/h","1 g/h"]'::jsonb, 0, NULL, true, NOW(), NOW());
