INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('clat8nz5h0e66fx4dqae62cca', 'tech', 'In welchem Zustand befindet sich Chlor in der Dosierleitung?', '["Gasförmig (nach Expansion durch das Dosiergerät)","Flüssig nach DIN 19643 im Routinebetrieb","Fest bei vorschriftsmäßigem Betrieb","Als Pulver durch Fachpersonal gemäß Betriebsanweisung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c04k4qctxppgcv0v3qeb2u302', 'tech', 'Was passiert, wenn die Temperatur an der Chlordosierleitung stark sinkt?', '["Chlorgas kann rückverflüssigen und die Dosierung unkontrolliert werden","Nichts passiert gemäß Gefährdungsbeurteilung im Normalbetrieb","Die Dosierung wird genauer laut RKI-Empfehlung","Das Chlor verdampft schneller durch Fachpersonal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cftd7beqoq8vvwwpfvznc1hdd', 'tech', 'Von welchen Einflüssen hängt die Dosiermenge des frei wirksamen Chlors ab?', '["Besucherzahl, Wassertemperatur, UV-Strahlung, Verschmutzungsgrad","Nur von der Uhrzeit laut RKI-Empfehlung nach Betriebsvorschrift","Von nichts nach Desinfektionsplan im Regelbetrieb","Nur vom Wetter bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cvzaq4bnpn0gyzvmdqovec0hm', 'tech', 'Welche Temperatur sollte im Chlorgas-Lagerraum herrschen?', '["Kühl, aber frostfrei (idealerweise unter 40°C)","Über 60°C wie vorgeschrieben gemäß Infektionsschutzgesetz","Egal welche Temperatur laut RKI-Empfehlung","Unter -20°C nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cce4exsd2nmtxbkf0v9x5ke89', 'tech', 'Was ist wichtig beim Wasserablauf/Bodeneinlauf im Chlorgas-Lagerraum?', '["Muss vorhanden sein für Berieselungsanlage, darf nicht in Kanalisation führen","Nicht nötig nach technischer Regel bei Standardbedingungen","Normaler Abfluss reicht nach aktueller Norm bei vorschriftsmäßigem Betrieb","Nur im Notfall wichtig im Routinebetrieb laut RKI-Empfehlung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cjp0vnwuzyonltl8eki6sbtla', 'tech', 'Wie muss die Ausgangstür des Chlorgas-Lagerraums sein?', '["Nach außen öffnend, feuerhemmend, von innen ohne Schlüssel zu öffnen","Nach innen öffnend im Rahmen der Betriebsführung","Aus Glas im Routinebetrieb nach Dienstanweisung","Ohne besondere Anforderungen laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cs88lgz5m5u11jqqa1u68lmly', 'tech', 'Wie wirkt Ozon als Desinfektionsmittel?', '["Sehr starkes Oxidationsmittel, wirkt gegen Bakterien, Viren und Pilze","Schwaches Desinfektionsmittel nach Herstellervorgabe","Nur gegen Algen im Regelbetrieb gemäß Gefährdungsbeurteilung","Gar nicht desinfizierend laut RKI-Empfehlung laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c7l8xzzhd59zwot1frznlztft', 'tech', 'Wie wird Ozon hergestellt?', '["Durch elektrische Entladung (stille Entladung) in Sauerstoff oder Luft","Durch Erhitzen von Wasser und dokumentieren im Routinebetrieb","Durch Mischen von Chemikalien nach DIN 19643 nach Dienstanweisung","Durch Filtrierung von Luft nach UVV im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c7hqrellkrmvf2psm3d1emq6n', 'tech', 'Was bedeutet "instabil" bei Ozon?', '["Ozon (O₃) zerfällt schnell wieder zu Sauerstoff (O₂)","Ozon ist sehr stabil nach geltender Vorschrift","Ozon explodiert leicht nach Trinkwasserverordnung","Ozon löst sich nicht in Wasser nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cfayagjm22ds07358er946go0', 'tech', 'Welche positiven Begleiterscheinungen hat die Desinfektion mit Ozon?', '["Abbau von Chloraminen, Verbesserung von Geruch/Geschmack, Mikroflockung","Keine positiven Effekte bei korrekter Anwendung","Nur Chlorproduktion bei Standardbedingungen unter Betriebsbedingungen","Nur Wassererwärmung gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cd3rkhpyo8pt6q6r84zy2mscp', 'tech', 'Was sind Hauptbestandteile einer Ozonungsanlage?', '["Ozongenerator, Lufttrocknung, Reaktionsbehälter, Restozonvernichter","Nur ein Generator gemäß Prüfprotokoll gemäß Infektionsschutzgesetz","Nur ein Tank im laufenden Betrieb nach Dienstanweisung","Nur eine Pumpe durch Fachpersonal im Rahmen der Betriebsführung"]'::jsonb, 0, NULL, true, NOW(), NOW());
