INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ct1tvvvt79ku3qo8kqhgfwlcr', 'tech', 'Warum benötigt man bei Ozonungsanlagen einen Restozonvernichter?', '["Ozon darf nicht ins Becken gelangen, da es in hohen Konzentrationen gesundheitsschädlich ist","Ozon ist ungefährlich laut Herstellerangaben im laufenden Betrieb","Nur aus wirtschaftlichen Gründen gemäß Gefährdungsbeurteilung","Nur wegen dem Geruch durch geschultes Personal nach UVV nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0jkdxlsh3itl9r1pxzk19h7u', 'tech', 'Womit wird Restozon vernichtet?', '["Durch Aktivkohlefilter oder thermische/katalytische Zersetzung","Durch Chlorzugabe im Rahmen der Eigenkontrolle","Durch Erhitzen auf 500°C unter Aufsicht nach Desinfektionsplan","Durch Einfrieren nach aktueller Norm bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('clgnol5filqtqrq9skrv0sx26', 'tech', 'Wie erreicht man bei Ozon-Desinfektion die Desinfektionskraft im Becken?', '["Nach der Ozonbehandlung wird Chlor als Depotdesinfektionsmittel zugegeben","Nur durch Ozon allein nach Wartungsplan nach UVV","Durch UV-Licht im Routinebetrieb laut RKI-Empfehlung","Durch Erhöhung der Temperatur nach Trinkwasserverordnung"]'::jsonb, 0, NULL, true, NOW(), NOW());
