INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cfo94em0ctnbmwbtz18t5qg4v', 'swim', 'Wodurch erfolgt der Vortrieb beim Brustschwimmen?', '["Hauptsächlich durch den Beinschlag (ca. 70%)","Nur durch den Armzug laut Herstellerangaben","Durch die Kopfbewegung bei korrekter Anwendung","Durch die Wasserlage im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
