INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c9xz0skqly66vg4wo8xn0v75q', 'swim', 'Was sollte ein Trainingsplan zur Verbesserung der allgemeinen Kondition beinhalten?', '["Ausdauer, Kraft, Schnelligkeit, Beweglichkeit, Koordination","Nur Ausdauer in regelmäßigen Abständen laut Herstellerangaben","Nur Kraft im Rahmen der Eigenkontrolle durch geschultes Personal","Nur Technik nach aktueller Norm nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c077hykzuci3qo12yyukvfr97', 'swim', 'Was beinhaltet ein Trainingsplan für schwimmerische Kondition?', '["Schwimmspezifische Ausdauer, Techniktraining, Schnelligkeitstraining","Nur Laufen nach Vorschrift laut RKI-Empfehlung","Nur Krafttraining an Land bei ordnungsgemäßem Betrieb","Nur Dehnen im Rahmen der Eigenkontrolle unter Betriebsbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ckalsbvc9k5wbpq6nrqu4tpyr', 'swim', 'Was ist der Unterschied zwischen Ausdauer und Kondition?', '["Ausdauer = Ermüdungswiderstand; Kondition = Summe aller körperlichen Leistungsfaktoren","Kein Unterschied im laufenden Betrieb bei ordnungsgemäßem Betrieb","Ausdauer ist wichtiger gemäß Infektionsschutzgesetz nach Dienstanweisung","Kondition ist nur Kraft laut Betriebshandbuch und dokumentieren"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c710xkhifaie4wzyxz5bpal6y', 'swim', 'Wie nutzt man die Pulsmessung zur Kontrolle der Trainingseffektivität?', '["Vergleich von Belastungs- und Erholungspuls","Nur einmal messen bei korrekter Anwendung","Ist nicht relevant bei ordnungsgemäßem Betrieb","Nur vor dem Training im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('czmzjmccoeb94vs0rmb8ezw3i', 'swim', 'Was ist der Unterschied zwischen aerobem und anaerobem Training?', '["Aerob: mit Sauerstoff, niedrige Intensität; Anaerob: ohne ausreichend Sauerstoff, hohe Intensität","Kein Unterschied bei vorschriftsmäßigem Betrieb nach Trinkwasserverordnung","Aerob ist schneller gemäß Betriebsanweisung nach Betriebsvorschrift","Anaerob ist langsamer nach Dienstanweisung im Routinebetrieb durch Fachpersonal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cs5hzbmk4scp2pfu4vfcslq86', 'swim', 'Was ist der Unterschied zwischen statischem und dynamischem Krafttraining?', '["Statisch: ohne Bewegung (Haltearbeit); Dynamisch: mit Bewegung","Kein Unterschied gemäß Betriebsanweisung im laufenden Betrieb","Statisch ist schwerer bei Standardbedingungen","Dynamisch ist leichter nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cu1x2xwhmj9fbewwuelxhhzvc', 'swim', 'Welche gesundheitlichen Vorteile hat Schwimmen?', '["Gelenkschonend, trainiert Herz-Kreislauf, verbessert Ausdauer","Keine Vorteile bei vorschriftsmäßigem Betrieb","Nur für Profis geeignet laut RKI-Empfehlung","Belastet die Gelenke unter Aufsicht nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c0m44wazz35mieoir5f6areaj', 'swim', 'Was ist der Unterschied zwischen Didaktik und Methodik?', '["Didaktik = Was wird gelehrt; Methodik = Wie wird gelehrt","Kein Unterschied gemäß Prüfprotokoll im Normalbetrieb","Didaktik ist Praxis in regelmäßigen Abständen","Methodik ist Theorie bei ordnungsgemäßem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
