INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c2um42l11ji5q0pj77g8ahkvd', 'swim', 'Wie führt man eine Eisrettung durch?', '["Flach auf das Eis legen, Hilfsmittel reichen, nie direkt zur Person gehen","Aufrecht zum Opfer gehen laut Betriebshandbuch nach Betriebsvorschrift","Ins Wasser springen bei korrekter Anwendung im Routinebetrieb","Auf das Eis springen bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
