INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cty1yoe1dy39b95rx6ccl8s80', 'first', 'Was unterscheidet einen Notfall von einer Notsituation?', '["Notfall = akute Lebensgefahr; Notsituation = keine unmittelbare Lebensgefahr","Kein Unterschied nach geltender Vorschrift nach technischer Regel","Notfall ist weniger schlimm im Regelbetrieb im Normalbetrieb","Notsituation ist gefährlicher durch geschultes Personal"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('czosk5qtgfnrcy94e58t476iv', 'first', 'Wie sichert man eine Unfallstelle im Badebetrieb ab?', '["Bereich absperren, Badegäste fernhalten, ggf. Becken räumen","Nichts tun nach geltender Vorschrift durch geschultes Personal","Weiterschwimmen lassen nach aktueller Norm","Nur zuschauen bei korrekter Anwendung gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c68etsxu52llkb62l5jfvofaq', 'first', 'Welche lebensrettenden Sofortmaßnahmen gibt es?', '["Bewusstsein prüfen, Atmung prüfen, Notruf, HLW, stabile Seitenlage","Nur Notruf im Regelbetrieb nach DIN 19643 unter Betriebsbedingungen","Nur warten durch geschultes Personal bei korrekter Anwendung","Nur Decke geben bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
