INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwtp36vn43s9y0ypyt4vrvthb', 'first', 'Was ist der Esmarch''sche Griff?', '["Handgriff zum Überstrecken des Kopfes und Anheben des Kinns","Ein Rettungsgriff im Wasser","Ein Tragegriff","Ein Befreiungsgriff"]'::jsonb, 0, NULL, true, NOW(), NOW());
