INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cuwv70czbi13190vqzriajv7m', 'first', 'Wie führt man die Mund-zu-Nase-Beatmung durch?', '["Kopf überstrecken, Mund zuhalten, durch die Nase beatmen","Nase zuhalten laut Betriebshandbuch nach Vorschrift","Wie Mund-zu-Mund gemäß Infektionsschutzgesetz","Ohne Kopfüberstreckung nach DIN 19643"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cufvh045hof4tcv1j0ci5ks7h', 'first', 'Was ist ein Vorteil der Mund-zu-Nase-Beatmung?', '["Mund des Opfers muss nicht geöffnet werden","Mehr Luft möglich nach geltender Vorschrift","Einfacher auszuführen durch geschultes Personal","Hygienischer nach Wartungsplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c18n15hca1x78v3g5rzbhkr1b', 'first', 'Was ist ein typischer Fehler bei der Atemspende?', '["Kopf nicht ausreichend überstreckt, Atemwege nicht frei","Zu langsam beatmen unter Aufsicht im Routinebetrieb","Zu viel Luft nach Desinfektionsplan nach technischer Regel","Zu hygienisch gemäß Prüfprotokoll nach Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmeki081pu57amw94hgs2usy4', 'first', 'Wie hoch sind Beatmungsfrequenz und -volumen beim Erwachsenen?', '["Ca. 10-12 Beatmungen/min, ca. 500-600 ml Volumen","5 Beatmungen/min, 200 ml unter Aufsicht","30 Beatmungen/min, 1000 ml nach Vorschrift","2 Beatmungen/min, 100 ml im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('clpy6biq3nhqbg2uf9rkygdna', 'first', 'Wie hoch sind Beatmungsfrequenz und -volumen beim 5-jährigen Kind?', '["Ca. 12-20 Beatmungen/min, kleineres Volumen als Erwachsene","Wie beim Erwachsenen nach Dienstanweisung","Nur 5 Beatmungen/min nach Trinkwasserverordnung","Doppelt so viel wie Erwachsene im Normalbetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cadsxaxqvfh9cna1eqx88ivfr', 'first', 'Wie beatmet man einen Säugling?', '["Mund und Nase umschließen, kleine Atemzüge, 20-30/min","Wie beim Erwachsenen in regelmäßigen Abständen","Nur durch die Nase nach Vorschrift gemäß Infektionsschutzgesetz","Gar nicht beatmen nach geltender Vorschrift"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cjincplbmxoavmrd3rvb50bzw', 'first', 'Wie führt man die Herzdruckmassage bei Erwachsenen durch?', '["Handballen auf Brustbeinmitte, 5-6 cm tief, 100-120/min","Auf den Bauch drücken nach Betriebsvorschrift","Nur 50 mal pro Minute laut RKI-Empfehlung","Mit einem Finger nach UVV durch den Betreiber"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cn3vtvi7n82mhuaxitdhqwia3', 'first', 'Wo ist der Druckpunkt für die Herzdruckmassage beim Erwachsenen?', '["Mitte des Brustkorbs (untere Brustbeinhälfte)","Auf dem Bauch nach DIN 19643 nach Herstellervorgabe","Am Hals in regelmäßigen Abständen","Auf der Schulter wie vorgeschrieben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5lop07k8k3bvziovm272bus6', 'first', 'Wie führt man die Herzdruckmassage bei Kleinkindern durch?', '["Ein Handballen, ca. 5 cm tief, auf untere Brustbeinhälfte","Wie beim Erwachsenen im Routinebetrieb","Gar nicht drücken gemäß Betriebsanweisung","Mit beiden Fäusten laut Herstellerangaben"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ci84n2glc2swv87c0r2phud9y', 'first', 'Wie führt man die Herzdruckmassage bei Säuglingen durch?', '["Zwei Finger auf Brustbeinmitte, ca. 4 cm tief","Mit der ganzen Hand nach geltender Vorschrift","Auf den Bauch drücken bei ordnungsgemäßem Betrieb","Gar nicht drücken im Rahmen der Eigenkontrolle"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c3c4hdvym1027oc1gk96nk6mt', 'first', 'Was ist ein häufiger Fehler bei der Herzdruckmassage?', '["Zu geringe Drucktiefe oder falsche Druckpunktposition","Zu schnell drücken im Rahmen der Betriebsführung","Zu tief drücken durch geschultes Personal","Zu wenig Pausen nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
