INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cmgh588z0hnwo945ymkucckvk', 'first', 'Was ist der diagnostische Block bei der HLW?', '["Bewusstsein prüfen, Hilfe rufen, Atemwege freimachen, Atmung prüfen","Nur Atmung prüfen nach technischer Regel nach Wartungsplan","Sofort mit Herzdruckmassage beginnen nach Desinfektionsplan","Nichts tun bei korrekter Anwendung im laufenden Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
