INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('cwu6sze4c2rf9web68is1u0kx', 'first', 'Wie bringt man jemanden in die stabile Seitenlage?', '["Arm anwinkeln, gegenüberliegendes Bein anwinkeln, zur Seite drehen, Kopf überstrecken","Einfach auf die Seite legen im laufenden Betrieb im Rahmen der Betriebsführung","Auf den Bauch drehen unter Aufsicht nach UVV im Rahmen der Eigenkontrolle","Sitzen lassen durch Fachpersonal laut Betriebshandbuch nach aktueller Norm"]'::jsonb, 0, NULL, true, NOW(), NOW());
