INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c3uvgr9cs76mzzcrn9tj5vapt', 'first', 'Was macht der Ersthelfer bei einer offenen Fraktur?', '["Wunde steril abdecken, Extremität ruhigstellen, Notruf","Knochen einrenken nach geltender Vorschrift","Stark bewegen nach Hygieneplan bei vorschriftsmäßigem Betrieb","Ignorieren gemäß Gefährdungsbeurteilung"]'::jsonb, 0, NULL, true, NOW(), NOW());
