INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c5n8hmqx8el7lgbirlphrxcaw', 'first', 'An welchen Symptomen erkennt man einen Schockzustand?', '["Blässe, kalter Schweiß, schneller flacher Puls, Unruhe, Bewusstseinstrübung","Rotes Gesicht im Routinebetrieb durch Fachpersonal","Langsamer Puls im Normalbetrieb nach geltender Vorschrift","Hunger nach DIN 19643 gemäß Infektionsschutzgesetz"]'::jsonb, 0, NULL, true, NOW(), NOW());
