INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1jyg22fin2xtzzve820c5bqv', 'first', 'Ein Mann erleidet beim Schwimmen einen Herzinfarkt und wird bewusstlos ohne Atmung geborgen. Was tun?', '["Sofort mit Wiederbelebung beginnen (30:2) und Notruf","Nur Notruf absetzen nach Herstellervorgabe","Warten bis er aufwacht nach Betriebsvorschrift","Wasser aus der Lunge drücken nach Hygieneplan"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ca0tksnv7i8rvcjd1aic61gng', 'first', 'Ein Badegast klagt nach dem Schwimmen über Brustschmerzen und Ausstrahlung in den Arm. Was tun?', '["Herzinfarkt-Verdacht: Oberkörper hoch lagern, beruhigen, Notruf, enge Kleidung öffnen","Weiterschwimmen lassen nach Hygieneplan laut Herstellerangaben","Kaltes Wasser geben bei vorschriftsmäßigem Betrieb im Regelbetrieb","Nichts tun gemäß Prüfprotokoll nach Betriebsvorschrift bei Standardbedingungen"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c1po2642ezp98h5p48qx8ml9v', 'first', 'Was unterscheidet Herzinfarkt von Angina Pectoris?', '["Herzinfarkt: dauerhafter Verschluss, Gewebe stirbt; Angina: vorübergehende Minderdurchblutung","Kein Unterschied nach Trinkwasserverordnung bei ordnungsgemäßem Betrieb","Angina ist schlimmer bei Standardbedingungen bei vorschriftsmäßigem Betrieb","Herzinfarkt ist harmlos im laufenden Betrieb nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
