INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c237paw5xehuowzhwkovh3w51', 'first', 'Was sind mögliche Ursachen für einen Akuten Bauch?', '["Blinddarmentzündung, Darmverschluss, innere Blutung, Gallenkolik","Nur Hunger nach Trinkwasserverordnung im Regelbetrieb","Nur Verstopfung bei ordnungsgemäßem Betrieb","Nur Durchfall im Normalbetrieb nach Herstellervorgabe"]'::jsonb, 0, NULL, true, NOW(), NOW());
INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('ct0c6wd8g3yn2trr5qbsbvygd', 'first', 'Welche Maßnahmen ergreift man bei Akutem Bauch?', '["Nichts zu essen/trinken geben, Schonlagerung, Notruf","Essen geben durch den Betreiber nach Vorschrift","Viel trinken lassen nach DIN 19643","Abwarten laut Betriebshandbuch im Routinebetrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
