INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('c58ak0l5pbt5jpcrtxbblswms', 'first', 'Was sind Maßnahmen bei Hitzschlag?', '["Sofort kühlen, Notruf 112, Schatten, Kleidung öffnen","Warm einpacken bei vorschriftsmäßigem Betrieb","Viel bewegen nach aktueller Norm unter Betriebsbedingungen","In die Sonne legen gemäß Prüfprotokoll"]'::jsonb, 0, NULL, true, NOW(), NOW());
