INSERT INTO "Question" (id, category, prompt, options, "correctOptionIndex", explanation, "isActive", "createdAt", "updatedAt") VALUES ('coxlwcwy21cmv6rtbk4vyh8ff', 'first', 'Welche Aufgabe hat die Ozonschicht der Erde?', '["Filtert schädliche UV-Strahlung der Sonne","Erzeugt Sauerstoff laut RKI-Empfehlung","Wärmt die Erde im Rahmen der Betriebsführung","Produziert Regen bei vorschriftsmäßigem Betrieb"]'::jsonb, 0, NULL, true, NOW(), NOW());
